import mongoose from "mongoose";
import * as dotenv from "dotenv";
import path from "path";
dotenv.config({ path: path.resolve(process.cwd(), ".env.local") });

const MONGODB_URI = process.env.MONGODB_URI;

if (!MONGODB_URI) {
    console.error("Γ¥î MONGODB_URI is not defined in .env.local");
    process.exit(1);
}
async function test() {
    console.log(`Testing connection to: ${MONGODB_URI?.split('@')[1]}`);
    try {
        await mongoose.connect(MONGODB_URI as string, { serverSelectionTimeoutMS: 5000 });
        console.log("SUCCESS: Connected to Atlas!");
        await mongoose.connection.close();
        process.exit(0);
    } catch (err: any) {
        console.error("FAILURE: Could not connect.");
        console.error("Error Name:", err.name);
        console.error("Error Message:", err.message);
        process.exit(1);
    }
}

test();

"use client";

import React, { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import {
    Wallet,
    Users,
    ShoppingBag,
    TrendingUp,
    CheckCircle,
    XCircle,
    Clock,
    ExternalLink,
    Copy,
    AlertTriangle
} from "lucide-react";

interface Withdrawal {
    _id: string;
    amount: number;
    status: "pending" | "processing" | "completed" | "rejected";
    upiId?: string;
    bankAccount?: {
        accountNumber: string;
        ifscCode: string;
        accountHolderName: string;
    };
    user: {
        _id: string;
        name: string;
        email: string;
    };
    createdAt: string;
    transactionId?: string;
}

interface Stats {
    pendingWithdrawals: number;
    completedOrders: number;
    totalUsers: number;
    platformEarnings: number;
}

export default function AdminPanel() {
    const router = useRouter();
    const [stats, setStats] = useState<Stats | null>(null);
    const [withdrawals, setWithdrawals] = useState<Withdrawal[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [processing, setProcessing] = useState<string | null>(null);
    const [copied, setCopied] = useState("");

    useEffect(() => {
        const token = localStorage.getItem("token");
        if (!token) {
            router.push("/login");
            return;
        }
        fetchData();
    }, [router]);

    const fetchData = async () => {
        try {
            const token = localStorage.getItem("token");
            const res = await fetch("/api/admin/dashboard", {
                headers: { Authorization: `Bearer ${token}` },
            });

            if (res.status === 403) {
                setError("Access denied. Admin privileges required.");
                setLoading(false);
                return;
            }

            const data = await res.json();
            if (data.error) {
                throw new Error(data.error);
            }

            setStats(data.stats);
            setWithdrawals(data.withdrawals);
        } catch (err) {
            setError(err instanceof Error ? err.message : "Failed to load");
        } finally {
            setLoading(false);
        }
    };

    const handleStatusUpdate = async (id: string, status: string, transactionId?: string) => {
        setProcessing(id);
        try {
            const token = localStorage.getItem("token");
            const res = await fetch(`/api/admin/withdrawals/${id}`, {
                method: "PUT",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${token}`,
                },
                body: JSON.stringify({ status, transactionId }),
            });

            if (!res.ok) {
                throw new Error("Failed to update");
            }

            fetchData();
        } catch (err) {
            alert("Error updating withdrawal");
        } finally {
            setProcessing(null);
        }
    };

    const copyToClipboard = (text: string, label: string) => {
        navigator.clipboard.writeText(text);
        setCopied(label);
        setTimeout(() => setCopied(""), 2000);
    };

    const markAsCompleted = (w: Withdrawal) => {
        const txnId = prompt("Enter transaction ID/reference (optional):");
        handleStatusUpdate(w._id, "completed", txnId || undefined);
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-900 flex items-center justify-center">
                <div className="animate-spin h-8 w-8 border-2 border-purple-500 border-t-transparent rounded-full" />
            </div>
        );
    }

    if (error) {
        return (
            <div className="min-h-screen bg-gray-900 flex items-center justify-center">
                <div className="text-center">
                    <AlertTriangle size={48} className="mx-auto text-red-500 mb-4" />
                    <p className="text-red-400 text-lg">{error}</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-900 text-white p-6">
            <div className="max-w-6xl mx-auto">
                {/* Header */}
                <div className="mb-8">
                    <h1 className="text-3xl font-bold bg-gradient-to-r from-purple-400 to-pink-500 bg-clip-text text-transparent">
                        Admin Panel
                    </h1>
                    <p className="text-gray-400 mt-1">CampusMarket Management</p>
                </div>

                {/* Stats Grid */}
                {stats && (
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
                        <div className="bg-gray-800 rounded-xl p-5 border border-gray-700">
                            <div className="flex items-center gap-3">
                                <div className="p-2 rounded-lg bg-amber-500/20">
                                    <Clock size={24} className="text-amber-500" />
                                </div>
                                <div>
                                    <p className="text-2xl font-bold">{stats.pendingWithdrawals}</p>
                                    <p className="text-xs text-gray-400">Pending Withdrawals</p>
                                </div>
                            </div>
                        </div>

                        <div className="bg-gray-800 rounded-xl p-5 border border-gray-700">
                            <div className="flex items-center gap-3">
                                <div className="p-2 rounded-lg bg-emerald-500/20">
                                    <ShoppingBag size={24} className="text-emerald-500" />
                                </div>
                                <div>
                                    <p className="text-2xl font-bold">{stats.completedOrders}</p>
                                    <p className="text-xs text-gray-400">Completed Orders</p>
                                </div>
                            </div>
                        </div>

                        <div className="bg-gray-800 rounded-xl p-5 border border-gray-700">
                            <div className="flex items-center gap-3">
                                <div className="p-2 rounded-lg bg-blue-500/20">
                                    <Users size={24} className="text-blue-500" />
                                </div>
                                <div>
                                    <p className="text-2xl font-bold">{stats.totalUsers}</p>
                                    <p className="text-xs text-gray-400">Total Users</p>
                                </div>
                            </div>
                        </div>

                        <div className="bg-gray-800 rounded-xl p-5 border border-gray-700">
                            <div className="flex items-center gap-3">
                                <div className="p-2 rounded-lg bg-purple-500/20">
                                    <TrendingUp size={24} className="text-purple-500" />
                                </div>
                                <div>
                                    <p className="text-2xl font-bold">Γé╣{stats.platformEarnings.toLocaleString()}</p>
                                    <p className="text-xs text-gray-400">Platform Earnings</p>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Withdrawals Section */}
                <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
                    <div className="p-5 border-b border-gray-700">
                        <h2 className="text-lg font-semibold flex items-center gap-2">
                            <Wallet size={20} />
                            Withdrawal Requests
                        </h2>
                    </div>

                    {withdrawals.length === 0 ? (
                        <div className="p-10 text-center text-gray-400">
                            No withdrawal requests yet
                        </div>
                    ) : (
                        <div className="divide-y divide-gray-700">
                            {withdrawals.map((w) => (
                                <div key={w._id} className="p-5 hover:bg-gray-750">
                                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                                        {/* User & Amount Info */}
                                        <div className="flex-1">
                                            <div className="flex items-center gap-3 mb-2">
                                                <span className="text-xl font-bold text-emerald-400">
                                                    Γé╣{w.amount.toLocaleString()}
                                                </span>
                                                <span className={`text-xs px-2 py-1 rounded-full capitalize ${w.status === "pending" ? "bg-amber-500/20 text-amber-400" :
                                                        w.status === "processing" ? "bg-blue-500/20 text-blue-400" :
                                                            w.status === "completed" ? "bg-emerald-500/20 text-emerald-400" :
                                                                "bg-red-500/20 text-red-400"
                                                    }`}>
                                                    {w.status}
                                                </span>
                                            </div>
                                            <p className="text-sm">{w.user.name}</p>
                                            <p className="text-xs text-gray-400">{w.user.email}</p>
                                            <p className="text-xs text-gray-500 mt-1">
                                                {new Date(w.createdAt).toLocaleString()}
                                            </p>
                                        </div>

                                        {/* Payment Details */}
                                        <div className="flex-1 bg-gray-900 rounded-lg p-3">
                                            {w.upiId ? (
                                                <div className="flex items-center justify-between">
                                                    <div>
                                                        <p className="text-xs text-gray-400">UPI ID</p>
                                                        <p className="font-mono">{w.upiId}</p>
                                                    </div>
                                                    <button
                                                        onClick={() => copyToClipboard(w.upiId!, "upi-" + w._id)}
                                                        className="p-2 hover:bg-gray-700 rounded"
                                                    >
                                                        {copied === "upi-" + w._id ? (
                                                            <CheckCircle size={16} className="text-emerald-400" />
                                                        ) : (
                                                            <Copy size={16} />
                                                        )}
                                                    </button>
                                                </div>
                                            ) : w.bankAccount ? (
                                                <div className="space-y-1">
                                                    <div className="flex justify-between">
                                                        <span className="text-xs text-gray-400">Account</span>
                                                        <div className="flex items-center gap-2">
                                                            <span className="font-mono text-sm">{w.bankAccount.accountNumber}</span>
                                                            <button
                                                                onClick={() => copyToClipboard(w.bankAccount!.accountNumber, "acc-" + w._id)}
                                                                className="p-1 hover:bg-gray-700 rounded"
                                                            >
                                                                {copied === "acc-" + w._id ? (
                                                                    <CheckCircle size={14} className="text-emerald-400" />
                                                                ) : (
                                                                    <Copy size={14} />
                                                                )}
                                                            </button>
                                                        </div>
                                                    </div>
                                                    <div className="flex justify-between">
                                                        <span className="text-xs text-gray-400">IFSC</span>
                                                        <span className="font-mono text-sm">{w.bankAccount.ifscCode}</span>
                                                    </div>
                                                    <div className="flex justify-between">
                                                        <span className="text-xs text-gray-400">Name</span>
                                                        <span className="text-sm">{w.bankAccount.accountHolderName}</span>
                                                    </div>
                                                </div>
                                            ) : null}
                                        </div>

                                        {/* Actions */}
                                        {w.status === "pending" && (
                                            <div className="flex gap-2">
                                                <button
                                                    onClick={() => markAsCompleted(w)}
                                                    disabled={processing === w._id}
                                                    className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-700 rounded-lg text-sm font-medium disabled:opacity-50"
                                                >
                                                    <CheckCircle size={16} />
                                                    Complete
                                                </button>
                                                <button
                                                    onClick={() => handleStatusUpdate(w._id, "rejected")}
                                                    disabled={processing === w._id}
                                                    className="flex items-center gap-2 px-4 py-2 bg-red-600/20 hover:bg-red-600/30 text-red-400 rounded-lg text-sm font-medium disabled:opacity-50"
                                                >
                                                    <XCircle size={16} />
                                                    Reject
                                                </button>
                                            </div>
                                        )}

                                        {w.status === "completed" && w.transactionId && (
                                            <div className="text-xs text-gray-400">
                                                Txn: {w.transactionId}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="mt-8 text-center text-gray-500 text-sm">
                    <p>≡ƒöÆ Admin Panel - Access Restricted</p>
                </div>
            </div>
        </div>
    );
}

import { NextRequest, NextResponse } from "next/server";
import { dbConnect } from "@/lib/db";
import { Withdrawal } from "@/models/Withdrawal";
import { User } from "@/models/User";
import { Order } from "@/models/Order";
import { verifyAccess } from "@/lib/auth";

// Middleware to check admin role
async function verifyAdmin(req: NextRequest) {
    const authHeader = req.headers.get("authorization");
    if (!authHeader?.startsWith("Bearer ")) {
        return null;
    }

    const token = authHeader.split(" ")[1];
    const payload = verifyAccess(token);

    await dbConnect();
    const user = await User.findById(payload.id);

    if (!user || user.role !== "admin") {
        return null;
    }

    return user;
}

import { cache, CACHE_TTL } from "@/lib/cache";

// GET /api/admin/dashboard - Get admin dashboard stats
export async function GET(req: NextRequest) {
    try {
        const admin = await verifyAdmin(req);
        if (!admin) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
        }

        const { searchParams } = new URL(req.url);
        const page = parseInt(searchParams.get("page") || "1");
        const limit = parseInt(searchParams.get("limit") || "10");

        // Cache expensive stats for 1 minute
        const statsCacheKey = "admin:dashboard:stats";
        let stats = cache.get<any>(statsCacheKey);

        if (!stats) {
            const [
                pendingWithdrawalsCount,
                completedOrders,
                totalUsers,
                platformEarnings
            ] = await Promise.all([
                Withdrawal.countDocuments({ status: "pending" }),
                Order.countDocuments({ orderStatus: "delivered" }),
                User.countDocuments(),
                Order.aggregate([
                    { $match: { orderStatus: "delivered" } },
                    { $group: { _id: null, total: { $sum: { $add: ["$buyerFee", "$sellerFee"] } } } }
                ])
            ]);

            stats = {
                pendingWithdrawals: pendingWithdrawalsCount,
                completedOrders,
                totalUsers,
                platformEarnings: platformEarnings[0]?.total || 0
            };

            cache.set(statsCacheKey, stats, CACHE_TTL.SHORT * 2); // 60s
        }

        // Get paginated withdrawals (always fresh)
        const skip = (page - 1) * limit;
        const [withdrawals, totalWithdrawals] = await Promise.all([
            Withdrawal.find()
                .sort({ createdAt: -1 })
                .skip(skip)
                .limit(limit)
                .populate("user", "name email"),
            Withdrawal.countDocuments()
        ]);

        return NextResponse.json({
            stats,
            withdrawals,
            pagination: {
                page,
                limit,
                total: totalWithdrawals,
                pages: Math.ceil(totalWithdrawals / limit)
            }
        });
    } catch (error) {
        console.error("Admin dashboard error:", error);
        return NextResponse.json({ error: "Failed to load dashboard" }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import jwt, { JwtPayload } from "jsonwebtoken";
import { dbConnect } from "@/lib/db";
import { User } from "@/models/User";
import { signAccess, signRefresh, setRefreshCookie } from "@/lib/auth";

const REFRESH_SECRET = process.env.REFRESH_SECRET!;

interface RefreshPayload extends JwtPayload {
    id: string;
}

// POST /api/auth/refresh - Refresh access token using refresh token
export async function POST(req: NextRequest) {
    try {
        // Get refresh token from cookie or body
        const refreshToken = req.cookies.get("refresh")?.value;

        // Also check body for mobile/API clients
        let bodyToken: string | undefined;
        try {
            const body = await req.json();
            bodyToken = body.refreshToken;
        } catch {
            // No body, use cookie
        }

        const token = refreshToken || bodyToken;

        if (!token) {
            return NextResponse.json(
                { error: "Refresh token required" },
                { status: 401 }
            );
        }

        // Verify refresh token
        let payload: RefreshPayload;
        try {
            payload = jwt.verify(token, REFRESH_SECRET) as RefreshPayload;
        } catch (error) {
            // Token expired or invalid
            return NextResponse.json(
                { error: "Invalid or expired refresh token. Please login again." },
                { status: 401 }
            );
        }

        await dbConnect();

        // Verify user still exists and is active
        const user = await User.findById(payload.id).select("_id name email role");
        if (!user) {
            return NextResponse.json(
                { error: "User not found" },
                { status: 401 }
            );
        }

        // Generate new tokens
        const newAccessToken = signAccess({ id: user._id.toString() });
        const newRefreshToken = signRefresh({ id: user._id.toString() });

        // Set new refresh token cookie
        await setRefreshCookie(newRefreshToken);

        return NextResponse.json({
            token: newAccessToken,
            refreshToken: newRefreshToken,
            user: {
                id: user._id,
                name: user.name,
                email: user.email,
            }
        });
    } catch (error) {
        console.error("Error refreshing token:", error);
        return NextResponse.json(
            { error: "Failed to refresh token" },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from "next/server";
import { dbConnect } from "@/lib/db";
import { Order } from "@/models/Order";
import { Product } from "@/models/Product";
import { User } from "@/models/User";
import { verifyAccessSafe } from "@/lib/auth";

// GET /api/orders/[id] - Get order details
export async function GET(
    req: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const authHeader = req.headers.get("authorization");
        if (!authHeader?.startsWith("Bearer ")) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const token = authHeader.split(" ")[1];
        const result = verifyAccessSafe(token);
        if (!result.success) {
            return NextResponse.json({ error: result.error }, { status: 401 });
        }
        const payload = result.payload;

        await dbConnect();
        const { id } = await params;

        const order = await Order.findById(id)
            .populate("product")
            .populate("buyer", "name phone email")
            .populate("seller", "name phone email")
            .lean() as {
                _id: string;
                buyer: { _id: string; name: string; phone?: string; email: string };
                seller: { _id: string; name: string; phone?: string; email: string };
                [key: string]: unknown;
            } | null;

        if (!order) {
            return NextResponse.json({ error: "Order not found" }, { status: 404 });
        }

        // Only buyer or seller can view order
        const isBuyer = order.buyer._id.toString() === payload.id;
        const isSeller = order.seller._id.toString() === payload.id;

        if (!isBuyer && !isSeller) {
            return NextResponse.json({ error: "Not authorized" }, { status: 403 });
        }

        return NextResponse.json({ order });
    } catch (error) {
        console.error("Error fetching order:", error);
        return NextResponse.json({ error: "Failed to fetch order" }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import { dbConnect } from "@/lib/db";
import { College } from "@/models/College";
import { cache } from "@/lib/cache";

// POST /api/seed - Seed initial colleges data
export async function POST(req: NextRequest) {
    console.log("POST /api/seed called");
    try {
        console.log("Seeding started...");
        await dbConnect();
        console.log("DB connected for seeding");

        const { searchParams } = new URL(req.url);
        const force = searchParams.get("force") === "true";
        console.log(`Force parameter: ${force}`);

        // Check if colleges already exist
        const existingCount = await College.countDocuments();
        console.log(`Existing colleges: ${existingCount}`);

        if (existingCount > 0 && !force) {
            console.log("Already seeded, stopping.");
            return NextResponse.json({
                message: "Colleges already seeded. Use ?force=true to overwrite.",
                count: existingCount
            });
        }

        if (force) {
            console.log("Forcing re-seed, cleaning collection...");
            try {
                await College.deleteMany({});
                console.log("Collection cleared");
            } catch (dropErr: any) {
                console.error("Delete failed:", dropErr.message);
            }
        }

        // Default delivery locations for all colleges
        const defaultLocations = [
            { name: "Main Gate", building: "Entrance" },
            { name: "Central Library", building: "Academic Block" },
            { name: "Student Canteen", building: "Food Court" },
            { name: "Messenger Area", building: "Admin Block" },
        ];

        // Seed colleges from user's provided list
        const colleges = [
            { name: "Bhagwan Parshuram Institute of Technology", shortCode: "BPIT", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "Bharati Vidyapeeth's College of Engineering", shortCode: "BVCOE", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "BM Institute of Engineering & Technology", shortCode: "BMIET", city: "Sonepat", deliveryLocations: defaultLocations },
            { name: "Delhi Institute of Technology & Management", shortCode: "DITM", city: "Sonepat", deliveryLocations: defaultLocations },
            { name: "Delhi Technical Campus", shortCode: "DTC", city: "Greater Noida", deliveryLocations: defaultLocations },
            { name: "Dr. Akhilesh Das Gupta Institute of Technology & Management", shortCode: "ADGITM", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "Greater Noida Institute of Technology", shortCode: "GNIT", city: "Greater Noida", deliveryLocations: defaultLocations },
            { name: "Guru Teg Bahadur Institute of Technology", shortCode: "GTBIT", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "HMR Institute of Technology & Management", shortCode: "HMRITM", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "JIMS Engineering Management Technical Campus", shortCode: "JEMTEC", city: "Greater Noida", deliveryLocations: defaultLocations },
            { name: "Maharaja Agrasen Institute of Technology", shortCode: "MAIT", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "Maharaja Surajmal Institute of Technology", shortCode: "MSIT", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "Mahavir Swami Institute of Technology", shortCode: "MVSIT", city: "Sonepat", deliveryLocations: defaultLocations },
            { name: "Trinity Institute of Innovations in Professional Studies", shortCode: "TIIPS", city: "Greater Noida", deliveryLocations: defaultLocations },
            { name: "University School of Chemical Technology, GGSIPU", shortCode: "USCT", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "University School of Information & Communication Technology, GGSIPU", shortCode: "USICT", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "Vivekananda Institute of Professional Studies", shortCode: "VIPS", city: "Delhi", deliveryLocations: defaultLocations },
            { name: "University School of Automation & Robotics, GGSIPU", shortCode: "USAR", city: "Delhi", deliveryLocations: defaultLocations },
        ];

        console.log(`Attempting to seed ${colleges.length} colleges individually...`);
        const results = [];
        const errors = [];

        for (const collegeData of colleges) {
            try {
                const newCollege = await College.create(collegeData);
                results.push(newCollege.shortCode);
                console.log(`Seeded: ${collegeData.shortCode}`);
            } catch (err: any) {
                console.error(`Error inserting ${collegeData.shortCode}:`, err.message);
                errors.push({ college: collegeData.shortCode, error: err.message });
            }
        }

        // Invalidate colleges cache
        cache.delete("colleges:all");
        console.log("Cache invalidated");

        if (errors.length > 0) {
            console.log(`Seeding finished with ${errors.length} errors`);
            return NextResponse.json({
                message: "Seed completed with some errors",
                seeded: results,
                failed: errors
            }, { status: 207 });
        }

        console.log("Seeding finished successfully");
        return NextResponse.json({
            message: force ? "Colleges replaced successfully" : "Colleges seeded successfully",
            count: results.length
        }, { status: 201 });
    } catch (error: any) {
        console.error("FATAL ERROR in seed route:", error.message);
        console.error(error.stack);
        return NextResponse.json({
            error: "Failed to seed colleges",
            details: error.message
        }, { status: 500 });
    }
}

"use client";

import React, { useEffect, useState, useCallback } from "react";
import { useSearchParams } from "next/navigation";
import { ProductCard, ProductCardSkeleton } from "@/components/ProductCard";
import { Button } from "@/components/ui/Button";
import { Card } from "@/components/ui/Card";
import { Select } from "@/components/ui/Select";
import { Input } from "@/components/ui/Input";
import { Badge } from "@/components/ui/Badge";
import {
    Search,
    SlidersHorizontal,
    X,
    BookOpen,
    Laptop,
    Shirt,
    Armchair,
    Dumbbell,
    Pencil,
    Package,
    ChevronDown
} from "lucide-react";

const categories = [
    { value: "", label: "All Categories" },
    { value: "books", label: "Books", icon: BookOpen },
    { value: "electronics", label: "Electronics", icon: Laptop },
    { value: "clothing", label: "Clothing", icon: Shirt },
    { value: "furniture", label: "Furniture", icon: Armchair },
    { value: "sports", label: "Sports", icon: Dumbbell },
    { value: "stationery", label: "Stationery", icon: Pencil },
    { value: "accessories", label: "Accessories", icon: Package },
    { value: "other", label: "Other", icon: Package },
];

const conditions = [
    { value: "", label: "Any Condition" },
    { value: "new", label: "New" },
    { value: "like-new", label: "Like New" },
    { value: "good", label: "Good" },
    { value: "fair", label: "Fair" },
];

const sortOptions = [
    { value: "newest", label: "Newest First" },
    { value: "oldest", label: "Oldest First" },
    { value: "price-low", label: "Price: Low to High" },
    { value: "price-high", label: "Price: High to Low" },
];

interface College {
    _id: string;
    name: string;
    shortCode: string;
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
interface Product {
    _id: string;
    title: string;
    price: number;
    images: string[];
    condition: string;
    status: string;
    category: string;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    seller?: any;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    college?: any;
    createdAt: string;
}

export default function BrowsePage() {
    const searchParams = useSearchParams();
    const [products, setProducts] = useState<Product[]>([]);
    const [colleges, setColleges] = useState<College[]>([]);
    const [loading, setLoading] = useState(true);
    const [showFilters, setShowFilters] = useState(false);

    // Filter states
    const [search, setSearch] = useState(searchParams.get("search") || "");
    const [category, setCategory] = useState(searchParams.get("category") || "");
    const [condition, setCondition] = useState("");
    const [college, setCollege] = useState("");
    const [minPrice, setMinPrice] = useState("");
    const [maxPrice, setMaxPrice] = useState("");
    const [sort, setSort] = useState("newest");

    // Pagination
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);

    // Active filters count
    const activeFilters = [category, condition, college, minPrice, maxPrice].filter(Boolean).length;

    // Fetch colleges
    useEffect(() => {
        fetch("/api/colleges")
            .then((res) => res.json())
            .then((data) => setColleges(data.colleges || []))
            .catch(console.error);
    }, []);

    // Fetch products
    const fetchProducts = useCallback(async () => {
        setLoading(true);
        try {
            const params = new URLSearchParams();
            if (search) params.set("search", search);
            if (category) params.set("category", category);
            if (condition) params.set("condition", condition);
            if (college) params.set("college", college);
            if (minPrice) params.set("minPrice", minPrice);
            if (maxPrice) params.set("maxPrice", maxPrice);
            params.set("sort", sort);
            params.set("page", page.toString());
            params.set("limit", "12");

            const res = await fetch(`/api/products?${params}`);
            const data = await res.json();

            setProducts(data.products || []);
            setTotalPages(data.pagination?.pages || 1);
        } catch (error) {
            console.error("Error fetching products:", error);
        } finally {
            setLoading(false);
        }
    }, [search, category, condition, college, minPrice, maxPrice, sort, page]);

    useEffect(() => {
        fetchProducts();
    }, [fetchProducts]);

    const clearFilters = () => {
        setCategory("");
        setCondition("");
        setCollege("");
        setMinPrice("");
        setMaxPrice("");
        setPage(1);
    };

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        setPage(1);
        fetchProducts();
    };

    return (
        <div className="min-h-screen py-4 sm:py-8">
            <div className="max-w-7xl mx-auto px-3 sm:px-6 lg:px-8">
                {/* Header */}
                <div className="mb-6 sm:mb-8">
                    <h1 className="text-2xl sm:text-3xl lg:text-4xl font-bold mb-1 sm:mb-2">Browse Products</h1>
                    <p className="text-sm sm:text-base text-muted-foreground">
                        Discover amazing deals from students at your campus
                    </p>
                </div>

                {/* Search and filters bar */}
                <div className="flex flex-col gap-3 sm:gap-4 mb-6 sm:mb-8">
                    {/* Search */}
                    <form onSubmit={handleSearch} className="w-full">
                        <div className="relative">
                            <Search size={18} className="absolute left-3 sm:left-4 top-1/2 -translate-y-1/2 text-muted-foreground" />
                            <input
                                type="text"
                                value={search}
                                onChange={(e) => setSearch(e.target.value)}
                                placeholder="Search products..."
                                className="w-full bg-card border border-border rounded-xl pl-10 sm:pl-12 pr-4 py-2.5 sm:py-3 text-sm sm:text-base focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/20"
                            />
                        </div>
                    </form>

                    {/* Filter toggle & Sort */}
                    <div className="flex gap-2 sm:gap-3">
                        <Button
                            variant={showFilters ? "primary" : "outline"}
                            onClick={() => setShowFilters(!showFilters)}
                            icon={<SlidersHorizontal size={16} />}
                            className="relative flex-1 sm:flex-none text-sm sm:text-base"
                        >
                            <span className="hidden sm:inline">Filters</span>
                            <span className="sm:hidden">Filter</span>
                            {activeFilters > 0 && (
                                <span className="absolute -top-1 -right-1 w-4 h-4 sm:w-5 sm:h-5 bg-accent text-white text-[10px] sm:text-xs rounded-full flex items-center justify-center">
                                    {activeFilters}
                                </span>
                            )}
                        </Button>

                        <Select
                            options={sortOptions}
                            value={sort}
                            onChange={(e) => setSort(e.target.value)}
                            className="flex-1 sm:flex-none sm:w-44 text-sm"
                        />
                    </div>
                </div>

                {/* Filters panel */}
                {showFilters && (
                    <Card variant="glass" className="p-4 sm:p-6 mb-6 sm:mb-8 animate-in slide-in-from-top-2">
                        <div className="flex items-center justify-between mb-3 sm:mb-4">
                            <h3 className="font-semibold text-sm sm:text-base">Filters</h3>
                            {activeFilters > 0 && (
                                <Button variant="ghost" size="sm" onClick={clearFilters} className="text-xs sm:text-sm">
                                    Clear all
                                </Button>
                            )}
                        </div>

                        <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-5 gap-3 sm:gap-4">
                            <Select
                                label="College"
                                options={[{ value: "", label: "All Colleges" }, ...colleges.map(c => ({ value: c._id, label: c.shortCode }))]}
                                value={college}
                                onChange={(e) => { setCollege(e.target.value); setPage(1); }}
                            />

                            <Select
                                label="Category"
                                options={categories}
                                value={category}
                                onChange={(e) => { setCategory(e.target.value); setPage(1); }}
                            />

                            <Select
                                label="Condition"
                                options={conditions}
                                value={condition}
                                onChange={(e) => { setCondition(e.target.value); setPage(1); }}
                            />

                            <Input
                                label="Min Γé╣"
                                type="number"
                                placeholder="0"
                                value={minPrice}
                                onChange={(e) => { setMinPrice(e.target.value); setPage(1); }}
                            />

                            <Input
                                label="Max Γé╣"
                                type="number"
                                placeholder="Any"
                                value={maxPrice}
                                onChange={(e) => { setMaxPrice(e.target.value); setPage(1); }}
                                className="col-span-2 sm:col-span-1"
                            />
                        </div>
                    </Card>
                )}

                {/* Active filter tags */}
                {activeFilters > 0 && (
                    <div className="flex flex-wrap gap-2 mb-6">
                        {category && (
                            <Badge variant="primary" className="flex items-center gap-1">
                                {categories.find(c => c.value === category)?.label}
                                <X size={14} className="cursor-pointer" onClick={() => setCategory("")} />
                            </Badge>
                        )}
                        {condition && (
                            <Badge variant="primary" className="flex items-center gap-1">
                                {conditions.find(c => c.value === condition)?.label}
                                <X size={14} className="cursor-pointer" onClick={() => setCondition("")} />
                            </Badge>
                        )}
                        {college && (
                            <Badge variant="primary" className="flex items-center gap-1">
                                {colleges.find(c => c._id === college)?.shortCode}
                                <X size={14} className="cursor-pointer" onClick={() => setCollege("")} />
                            </Badge>
                        )}
                        {minPrice && (
                            <Badge variant="primary" className="flex items-center gap-1">
                                Min Γé╣{minPrice}
                                <X size={14} className="cursor-pointer" onClick={() => setMinPrice("")} />
                            </Badge>
                        )}
                        {maxPrice && (
                            <Badge variant="primary" className="flex items-center gap-1">
                                Max Γé╣{maxPrice}
                                <X size={14} className="cursor-pointer" onClick={() => setMaxPrice("")} />
                            </Badge>
                        )}
                    </div>
                )}

                {/* Category pills (quick filter) - Horizontal scroll on mobile */}
                <div className="-mx-3 sm:mx-0 px-3 sm:px-0 mb-6 sm:mb-8">
                    <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide snap-x snap-mandatory sm:flex-wrap sm:overflow-visible">
                        {categories.slice(1).map((cat) => (
                            <button
                                key={cat.value}
                                onClick={() => { setCategory(category === cat.value ? "" : cat.value); setPage(1); }}
                                className={`category-pill whitespace-nowrap snap-start flex-shrink-0 text-xs sm:text-sm py-2 px-3 sm:py-2.5 sm:px-4 ${category === cat.value ? "active" : ""}`}
                            >
                                {cat.icon && <cat.icon size={14} className="sm:w-4 sm:h-4" />}
                                {cat.label}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Products grid */}
                {loading ? (
                    <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 sm:gap-4 lg:gap-6">
                        {Array.from({ length: 8 }).map((_, i) => (
                            <ProductCardSkeleton key={i} />
                        ))}
                    </div>
                ) : products.length === 0 ? (
                    <Card variant="glass" className="p-12 text-center">
                        <div className="w-20 h-20 mx-auto mb-6 rounded-full bg-muted flex items-center justify-center">
                            <Package size={40} className="text-muted-foreground" />
                        </div>
                        <h3 className="text-xl font-semibold mb-2">No products found</h3>
                        <p className="text-muted-foreground mb-6">
                            Try adjusting your filters or search terms
                        </p>
                        <Button variant="outline" onClick={clearFilters}>
                            Clear Filters
                        </Button>
                    </Card>
                ) : (
                    <>
                        <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 sm:gap-4 lg:gap-6">
                            {products.map((product, index) => (
                                <div
                                    key={product._id}
                                    className="fade-in-up"
                                    style={{ animationDelay: `${index * 30}ms` }}
                                >
                                    <ProductCard product={product} />
                                </div>
                            ))}
                        </div>

                        {/* Pagination */}
                        {totalPages > 1 && (
                            <div className="flex items-center justify-center gap-2 mt-12">
                                <Button
                                    variant="outline"
                                    disabled={page === 1}
                                    onClick={() => setPage(page - 1)}
                                >
                                    Previous
                                </Button>
                                <span className="px-4 text-muted-foreground">
                                    Page {page} of {totalPages}
                                </span>
                                <Button
                                    variant="outline"
                                    disabled={page === totalPages}
                                    onClick={() => setPage(page + 1)}
                                >
                                    Next
                                </Button>
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";
import { Card } from "@/components/ui/Card";
import { Select } from "@/components/ui/Select";
import { Avatar } from "@/components/ui/Avatar";
import { AgreementModal } from "@/components/AgreementModal";
import {
    ArrowLeft,
    Shield,
    MapPin,
    Clock,
    Wallet,
    CreditCard,
    AlertCircle,
    CheckCircle,
    Phone,
    MessageCircle,
    Calendar
} from "lucide-react";
import Link from "next/link";

declare global {
    interface Window {
        Razorpay: any;
    }
}

interface DeliveryLocation {
    name: string;
    building: string;
}

interface Seller {
    _id: string;
    name: string;
    phone?: string;
}

interface Product {
    _id: string;
    title: string;
    description: string;
    price: number;
    images: string[];
    condition: string;
    seller: Seller;
    college: {
        _id: string;
        name: string;
        deliveryLocations: DeliveryLocation[];
    };
    availableDays?: string[];
    availableTimeStart?: string;
    availableTimeEnd?: string;
    availableNote?: string;
}

export default function CheckoutPage({ params }: { params: Promise<{ productId: string }> }) {
    const { productId } = use(params);
    const router = useRouter();
    const [product, setProduct] = useState<Product | null>(null);
    const [loading, setLoading] = useState(true);
    const [processing, setProcessing] = useState(false);
    const [selectedLocation, setSelectedLocation] = useState("");
    const [selectedTime, setSelectedTime] = useState("");
    const [showAgreement, setShowAgreement] = useState(false);
    const [paymentSuccess, setPaymentSuccess] = useState(false);
    const [sellerContact, setSellerContact] = useState<{ name: string; phone: string } | null>(null);
    const [orderId, setOrderId] = useState<string | null>(null);
    const [user, setUser] = useState<{ id: string; name: string; email: string } | null>(null);

    // Fee calculations
    const productPrice = product?.price || 0;
    const buyerFee = Math.round(productPrice * 0.05);
    const sellerFee = Math.round(productPrice * 0.05);
    const totalAmount = productPrice + buyerFee;
    const sellerReceives = productPrice - sellerFee;

    useEffect(() => {
        // Load Razorpay script
        const script = document.createElement("script");
        script.src = "https://checkout.razorpay.com/v1/checkout.js";
        script.async = true;
        document.body.appendChild(script);

        return () => {
            document.body.removeChild(script);
        };
    }, []);

    useEffect(() => {
        const token = localStorage.getItem("token");
        if (!token) {
            router.push(`/login?redirect=/checkout/${productId}`);
            return;
        }

        const userData = localStorage.getItem("user");
        if (userData) {
            setUser(JSON.parse(userData));
        }

        fetchProduct();
    }, [productId, router]);

    const fetchProduct = async () => {
        try {
            const res = await fetch(`/api/products/${productId}`);
            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error);
            }

            setProduct(data.product);
        } catch (error) {
            console.error("Error fetching product:", error);
            router.push("/browse");
        } finally {
            setLoading(false);
        }
    };

    const handleProceedToPayment = () => {
        if (!selectedLocation || !selectedTime) {
            alert("Please select delivery location and time");
            return;
        }
        setShowAgreement(true);
    };

    const handleAgreementAccept = async (terms: string, signature: string) => {
        setShowAgreement(false);
        setProcessing(true);

        try {
            const token = localStorage.getItem("token");

            // Create payment order
            const createRes = await fetch("/api/payments/create", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${token}`,
                },
                body: JSON.stringify({ productId }),
            });

            const createData = await createRes.json();

            if (!createRes.ok) {
                throw new Error(createData.error || "Failed to create payment");
            }

            // Get delivery location
            const location = product?.college?.deliveryLocations.find(
                l => `${l.name} - ${l.building}` === selectedLocation
            );

            // Check if simulated mode
            if (createData.simulated) {
                // Simulated payment - skip Razorpay, go directly to verification
                const verifyRes = await fetch("/api/payments/verify", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        Authorization: `Bearer ${token}`,
                    },
                    body: JSON.stringify({
                        razorpayOrderId: createData.orderId,
                        razorpayPaymentId: `sim_pay_${Date.now()}`,
                        razorpaySignature: "simulated",
                        productId,
                        deliveryLocation: location || { name: selectedLocation, building: "" },
                        deliveryTime: selectedTime,
                        agreementTerms: terms,
                        buyerSignature: signature,
                        simulated: true,
                    }),
                });

                const verifyData = await verifyRes.json();

                if (verifyData.success) {
                    setPaymentSuccess(true);
                    setSellerContact(verifyData.sellerContact);
                    setOrderId(verifyData.order._id);
                } else {
                    throw new Error("Verification failed");
                }
                return;
            }

            // Real Razorpay checkout
            const options = {
                key: createData.keyId,
                amount: createData.amount * 100,
                currency: createData.currency,
                name: "CampusMarket",
                description: `Purchase: ${product?.title}`,
                order_id: createData.orderId,
                handler: async function (response: any) {
                    const verifyRes = await fetch("/api/payments/verify", {
                        method: "POST",
                        headers: {
                            "Content-Type": "application/json",
                            Authorization: `Bearer ${token}`,
                        },
                        body: JSON.stringify({
                            razorpayOrderId: response.razorpay_order_id,
                            razorpayPaymentId: response.razorpay_payment_id,
                            razorpaySignature: response.razorpay_signature,
                            productId,
                            deliveryLocation: location || { name: selectedLocation, building: "" },
                            deliveryTime: selectedTime,
                            agreementTerms: terms,
                            buyerSignature: signature,
                            simulated: false,
                        }),
                    });

                    const verifyData = await verifyRes.json();

                    if (verifyData.success) {
                        setPaymentSuccess(true);
                        setSellerContact(verifyData.sellerContact);
                        setOrderId(verifyData.order._id);
                    } else {
                        throw new Error("Payment verification failed");
                    }
                },
                prefill: {
                    name: user?.name || "",
                    email: user?.email || "",
                },
                theme: {
                    color: "#6366f1",
                },
                modal: {
                    ondismiss: function () {
                        setProcessing(false);
                    },
                },
            };

            const razorpay = new window.Razorpay(options);
            razorpay.open();
        } catch (error) {
            console.error("Payment error:", error);
            alert("Payment failed. Please try again.");
            setProcessing(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <div className="animate-spin h-8 w-8 border-2 border-primary border-t-transparent rounded-full" />
            </div>
        );
    }

    if (!product) {
        return null;
    }

    // Payment Success View
    if (paymentSuccess && sellerContact) {
        return (
            <div className="min-h-screen py-8">
                <div className="max-w-2xl mx-auto px-4">
                    <Card variant="glass" className="p-8 text-center">
                        <div className="w-20 h-20 mx-auto rounded-full bg-gradient-to-br from-emerald-500 to-teal-500 flex items-center justify-center mb-6">
                            <CheckCircle size={40} className="text-white" />
                        </div>

                        <h1 className="text-2xl font-bold mb-2">Payment Successful!</h1>
                        <p className="text-muted-foreground mb-8">
                            Your payment is held securely in escrow until you confirm delivery.
                        </p>

                        {/* Order summary */}
                        <div className="p-4 rounded-xl bg-muted/30 mb-6 text-left">
                            <h3 className="font-medium mb-3">Order Summary</h3>
                            <div className="flex gap-4">
                                <img
                                    src={product.images[0] || "/placeholder.jpg"}
                                    alt={product.title}
                                    className="w-20 h-20 rounded-lg object-cover"
                                />
                                <div>
                                    <p className="font-medium">{product.title}</p>
                                    <p className="text-sm text-muted-foreground mt-1">
                                        {selectedLocation}
                                    </p>
                                    <p className="text-lg font-bold text-primary mt-2">
                                        Γé╣{totalAmount.toLocaleString()}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* Seller Contact - revealed after payment */}
                        <Card variant="gradient" className="p-6 mb-6">
                            <div className="flex items-center gap-2 mb-4">
                                <Phone size={20} className="text-primary" />
                                <h3 className="font-semibold">Contact Seller</h3>
                            </div>

                            <div className="flex items-center gap-4 mb-4">
                                <Avatar name={sellerContact.name} size="lg" />
                                <div className="text-left">
                                    <p className="font-medium text-lg">{sellerContact.name}</p>
                                    <p className="text-primary font-mono text-lg">{sellerContact.phone || "Phone not available"}</p>
                                </div>
                            </div>

                            <p className="text-sm text-muted-foreground mb-4">
                                Coordinate with the seller to arrange pickup at your selected location and time.
                            </p>

                            {sellerContact.phone && (
                                <div className="flex gap-3">
                                    <Button
                                        variant="primary"
                                        className="flex-1"
                                        icon={<Phone size={18} />}
                                        onClick={() => window.open(`tel:${sellerContact.phone}`)}
                                    >
                                        Call Seller
                                    </Button>
                                    <Button
                                        variant="outline"
                                        className="flex-1"
                                        icon={<MessageCircle size={18} />}
                                        onClick={() => window.open(`https://wa.me/91${sellerContact.phone?.replace(/\D/g, '')}`)}
                                    >
                                        WhatsApp
                                    </Button>
                                </div>
                            )}
                        </Card>

                        {/* Important notes */}
                        <div className="p-4 rounded-xl bg-amber-500/10 border border-amber-500/20 text-left mb-6">
                            <div className="flex items-start gap-3">
                                <AlertCircle size={20} className="text-amber-500 flex-shrink-0 mt-0.5" />
                                <div className="text-sm">
                                    <p className="font-medium text-amber-200 mb-1">Important</p>
                                    <ul className="list-disc list-inside text-muted-foreground space-y-1">
                                        <li>Inspect the product carefully before confirming delivery</li>
                                        <li>Payment will be released to seller after you confirm receipt</li>
                                        <li>Contact support if there are any issues</li>
                                    </ul>
                                </div>
                            </div>
                        </div>

                        <Link href="/dashboard">
                            <Button variant="outline" className="w-full">
                                Go to Dashboard
                            </Button>
                        </Link>
                    </Card>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen py-8">
            <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
                {/* Header */}
                <div className="flex items-center gap-4 mb-8">
                    <button
                        onClick={() => router.back()}
                        className="p-2 rounded-full hover:bg-muted transition-colors"
                    >
                        <ArrowLeft size={24} />
                    </button>
                    <h1 className="text-2xl font-bold">Checkout</h1>
                </div>

                <div className="grid lg:grid-cols-3 gap-8">
                    {/* Main Content */}
                    <div className="lg:col-span-2 space-y-6">
                        {/* Product Summary */}
                        <Card variant="glass" className="p-6">
                            <h2 className="font-semibold mb-4">Product</h2>
                            <div className="flex gap-4">
                                <img
                                    src={product.images[0] || "/placeholder.jpg"}
                                    alt={product.title}
                                    className="w-24 h-24 rounded-lg object-cover"
                                />
                                <div>
                                    <h3 className="font-medium">{product.title}</h3>
                                    <p className="text-sm text-muted-foreground mt-1 line-clamp-2">
                                        {product.description}
                                    </p>
                                    <div className="flex items-center gap-3 mt-2">
                                        <Avatar name={product.seller.name} size="sm" />
                                        <span className="text-sm">{product.seller.name}</span>
                                    </div>
                                </div>
                            </div>

                            {/* Seller Availability */}
                            {product.availableDays && product.availableDays.length > 0 && (
                                <div className="mt-4 pt-4 border-t border-border">
                                    <div className="flex items-center gap-2 mb-2">
                                        <Calendar size={16} className="text-primary" />
                                        <span className="text-sm font-medium">Seller Availability</span>
                                    </div>
                                    <p className="text-sm text-muted-foreground">
                                        {product.availableDays.map(d => d.charAt(0).toUpperCase() + d.slice(1, 3)).join(", ")}
                                        {product.availableTimeStart && product.availableTimeEnd && (
                                            <span> ΓÇó {product.availableTimeStart} - {product.availableTimeEnd}</span>
                                        )}
                                    </p>
                                    {product.availableNote && (
                                        <p className="text-xs text-muted-foreground mt-1 italic">
                                            "{product.availableNote}"
                                        </p>
                                    )}
                                </div>
                            )}
                        </Card>

                        {/* Delivery Location */}
                        <Card variant="glass" className="p-6">
                            <div className="flex items-center gap-2 mb-4">
                                <MapPin size={20} className="text-primary" />
                                <h2 className="font-semibold">Delivery Location</h2>
                            </div>
                            <Select
                                label="Select pickup point"
                                value={selectedLocation}
                                onChange={(e) => setSelectedLocation(e.target.value)}
                                options={[
                                    { value: "", label: "Choose a location" },
                                    ...(product.college?.deliveryLocations?.map(loc => ({
                                        value: `${loc.name} - ${loc.building}`,
                                        label: `${loc.name} - ${loc.building}`
                                    })) || [])
                                ]}
                            />
                        </Card>

                        {/* Delivery Time */}
                        <Card variant="glass" className="p-6">
                            <div className="flex items-center gap-2 mb-4">
                                <Clock size={20} className="text-primary" />
                                <h2 className="font-semibold">Preferred Time</h2>
                            </div>
                            <input
                                type="datetime-local"
                                value={selectedTime}
                                onChange={(e) => setSelectedTime(e.target.value)}
                                className="w-full bg-input border border-border rounded-lg px-4 py-3 focus:outline-none focus:border-primary"
                                min={new Date().toISOString().slice(0, 16)}
                            />
                            <p className="text-xs text-muted-foreground mt-2">
                                Coordinate with seller's availability shown above
                            </p>
                        </Card>

                        {/* Escrow Info */}
                        <Card className="p-4 bg-emerald-500/10 border border-emerald-500/20">
                            <div className="flex items-start gap-3">
                                <Shield size={24} className="text-emerald-500 flex-shrink-0" />
                                <div>
                                    <h3 className="font-medium text-emerald-400">Secure Escrow Payment</h3>
                                    <p className="text-sm text-muted-foreground mt-1">
                                        Your payment is held safely until you receive and confirm the product.
                                        No Cash on Delivery - 100% secure transactions.
                                    </p>
                                </div>
                            </div>
                        </Card>
                    </div>

                    {/* Order Summary Sidebar */}
                    <div className="lg:col-span-1">
                        <Card variant="glass" className="p-6 sticky top-24">
                            <h2 className="font-semibold mb-4">Order Summary</h2>

                            <div className="space-y-3 text-sm">
                                <div className="flex justify-between">
                                    <span className="text-muted-foreground">Product Price</span>
                                    <span>Γé╣{productPrice.toLocaleString()}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-muted-foreground">Platform Fee (5%)</span>
                                    <span>Γé╣{buyerFee.toLocaleString()}</span>
                                </div>
                                <div className="flex justify-between pt-3 border-t border-border text-lg font-semibold">
                                    <span>Total</span>
                                    <span className="text-primary">Γé╣{totalAmount.toLocaleString()}</span>
                                </div>
                            </div>

                            <div className="mt-4 p-3 rounded-lg bg-muted/30 text-xs text-muted-foreground">
                                <p>Seller receives: Γé╣{sellerReceives.toLocaleString()} (after 5% fee)</p>
                            </div>

                            <Button
                                variant="accent"
                                className="w-full mt-6"
                                size="lg"
                                onClick={handleProceedToPayment}
                                loading={processing}
                                disabled={!selectedLocation || !selectedTime}
                                icon={<CreditCard size={20} />}
                            >
                                Proceed to Pay
                            </Button>

                            <div className="flex items-center justify-center gap-2 mt-4 text-xs text-muted-foreground">
                                <Wallet size={14} />
                                <span>Powered by Razorpay</span>
                            </div>
                        </Card>
                    </div>
                </div>
            </div>

            {/* Agreement Modal */}
            {user && product && (
                <AgreementModal
                    isOpen={showAgreement}
                    onClose={() => setShowAgreement(false)}
                    onAccept={handleAgreementAccept}
                    product={{ title: product.title, price: productPrice }}
                    seller={{ name: product.seller.name }}
                    buyer={{ name: user.name }}
                    totalAmount={totalAmount}
                    buyerFee={buyerFee}
                    sellerFee={sellerFee}
                />
            )}
        </div>
    );
}

"use client";

import React, { useEffect, useState, useCallback } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Button } from "@/components/ui/Button";
import { Card } from "@/components/ui/Card";
import { Avatar } from "@/components/ui/Avatar";
import { StatusBadge } from "@/components/ui/Badge";
import { useAuth } from "@/context/AuthContext";
import {
    Package,
    ShoppingBag,
    DollarSign,
    Clock,
    PlusCircle,
    CheckCircle,
    XCircle,
    Truck,
    Eye,
    Wallet,
    TrendingUp
} from "lucide-react";

type TabType = "listings" | "purchases" | "sales";

interface Product {
    _id: string;
    title: string;
    price: number;
    images: string[];
    status: string;
    category: string;
    createdAt: string;
}

interface Order {
    _id: string;
    product: {
        _id: string;
        title: string;
        images: string[];
        price: number;
    };
    buyer?: {
        name: string;
        phone?: string;
    };
    seller?: {
        name: string;
        phone?: string;
    };
    amount: number;
    orderStatus: string;
    paymentStatus: string;
    deliveryLocation: {
        name: string;
        building: string;
    };
    deliveryTime: string;
    createdAt: string;
}

interface UserData {
    id: string;
    name: string;
    email: string;
    wallet: number;
    profileImage?: string;
    college?: {
        name: string;
        shortCode: string;
    };
}

export default function DashboardPage() {
    const router = useRouter();
    const { user, isAuthenticated, isLoading: authLoading, getToken, logout } = useAuth();
    const [activeTab, setActiveTab] = useState<TabType>("listings");
    const [userData, setUserData] = useState<UserData | null>(null);
    const [listings, setListings] = useState<Product[]>([]);
    const [purchases, setPurchases] = useState<Order[]>([]);
    const [sales, setSales] = useState<Order[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchData = useCallback(async () => {
        try {
            const token = await getToken();
            if (!token) {
                logout();
                return;
            }

            const headers = { Authorization: `Bearer ${token}` };

            const [listingsRes, purchasesRes, salesRes] = await Promise.all([
                fetch("/api/user/products", { headers }),
                fetch("/api/orders?role=buyer", { headers }),
                fetch("/api/orders?role=seller", { headers }),
            ]);

            // Handle 401 responses
            if (listingsRes.status === 401 || purchasesRes.status === 401 || salesRes.status === 401) {
                logout();
                return;
            }

            const [listingsData, purchasesData, salesData] = await Promise.all([
                listingsRes.json(),
                purchasesRes.json(),
                salesRes.json(),
            ]);

            setListings(listingsData.products || []);
            setPurchases(purchasesData.orders || []);
            setSales(salesData.orders || []);
        } catch (error) {
            console.error("Error fetching dashboard data:", error);
        } finally {
            setLoading(false);
        }
    }, [getToken, logout]);

    useEffect(() => {
        if (authLoading) return;

        if (!isAuthenticated) {
            router.push("/login?redirect=/dashboard");
            return;
        }

        if (user) {
            setUserData(user as UserData);
        }

        fetchData();
    }, [authLoading, isAuthenticated, user, router, fetchData]);

    const handleOrderAction = async (orderId: string, action: "confirm" | "delivered" | "cancel") => {
        try {
            const token = await getToken();
            if (!token) {
                logout();
                return;
            }

            const res = await fetch(`/api/orders/${orderId}/${action}`, {
                method: "POST",
                headers: { Authorization: `Bearer ${token}` },
            });

            const data = await res.json();

            if (!res.ok) {
                if (res.status === 401) {
                    logout();
                    return;
                }
                throw new Error(data.error);
            }

            // Refresh orders
            const [purchasesRes, salesRes] = await Promise.all([
                fetch("/api/orders?role=buyer", { headers: { Authorization: `Bearer ${token}` } }),
                fetch("/api/orders?role=seller", { headers: { Authorization: `Bearer ${token}` } }),
            ]);

            const [purchasesData, salesData] = await Promise.all([
                purchasesRes.json(),
                salesRes.json(),
            ]);

            setPurchases(purchasesData.orders || []);
            setSales(salesData.orders || []);

            // Update wallet if payment released
            if (action === "delivered") {
                const meRes = await fetch("/api/auth/me", { headers: { Authorization: `Bearer ${token}` } });
                const meData = await meRes.json();
                if (meData.user) {
                    localStorage.setItem("user", JSON.stringify({
                        ...userData,
                        wallet: meData.user.wallet
                    }));
                    setUserData((prev: UserData | null) => prev ? { ...prev, wallet: meData.user.wallet } : null);
                }
            }

            alert(data.message || "Action completed successfully!");
        } catch (error) {
            console.error("Error:", error);
            alert("Action failed. Please try again.");
        }
    };

    const stats = [
        {
            label: "Active Listings",
            value: listings.filter(p => p.status === "available").length,
            icon: Package,
            color: "from-indigo-500 to-violet-500"
        },
        {
            label: "Pending Orders",
            value: sales.filter(o => o.orderStatus === "placed" || o.orderStatus === "confirmed").length,
            icon: Clock,
            color: "from-amber-500 to-orange-500"
        },
        {
            label: "Completed Sales",
            value: sales.filter(o => o.orderStatus === "delivered").length,
            icon: TrendingUp,
            color: "from-emerald-500 to-teal-500"
        },
    ];

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin" />
            </div>
        );
    }

    return (
        <div className="min-h-screen py-8">
            <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
                {/* Header */}
                <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8">
                    <div className="flex items-center gap-4">
                        <Avatar src={userData?.profileImage} name={userData?.name || "User"} size="xl" />
                        <div>
                            <h1 className="text-2xl font-bold">{userData?.name}</h1>
                            {userData?.college && (
                                <span className="text-sm text-primary">{userData.college.shortCode}</span>
                            )}
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        <Card variant="gradient" className="px-4 py-2 flex items-center gap-2">
                            <Wallet size={20} className="text-emerald-500" />
                            <span className="text-sm text-muted-foreground">Wallet:</span>
                            <span className="font-bold text-emerald-500">Γé╣{(userData?.wallet || 0).toLocaleString()}</span>
                        </Card>
                        <Link href="/sell">
                            <Button variant="primary" icon={<PlusCircle size={18} />}>
                                Sell Item
                            </Button>
                        </Link>
                    </div>
                </div>

                {/* Stats */}
                <div className="grid sm:grid-cols-3 gap-4 mb-8">
                    {stats.map((stat) => (
                        <Card key={stat.label} variant="glass" className="p-6">
                            <div className="flex items-center gap-4">
                                <div className={`w-12 h-12 rounded-xl bg-gradient-to-br ${stat.color} flex items-center justify-center`}>
                                    <stat.icon size={24} className="text-white" />
                                </div>
                                <div>
                                    <p className="text-2xl font-bold">{stat.value}</p>
                                    <p className="text-sm text-muted-foreground">{stat.label}</p>
                                </div>
                            </div>
                        </Card>
                    ))}
                </div>

                {/* Tabs */}
                <div className="flex gap-2 mb-6 border-b border-border overflow-x-auto">
                    {[
                        { id: "listings" as TabType, label: "My Listings", icon: Package, count: listings.length },
                        { id: "purchases" as TabType, label: "My Purchases", icon: ShoppingBag, count: purchases.length },
                        { id: "sales" as TabType, label: "My Sales", icon: DollarSign, count: sales.length },
                    ].map((tab) => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${activeTab === tab.id
                                ? "border-primary text-primary"
                                : "border-transparent text-muted-foreground hover:text-foreground"
                                }`}
                        >
                            <tab.icon size={18} />
                            {tab.label}
                            {tab.count > 0 && (
                                <span className="px-2 py-0.5 rounded-full bg-muted text-xs">
                                    {tab.count}
                                </span>
                            )}
                        </button>
                    ))}
                </div>

                {/* Content */}
                {activeTab === "listings" && (
                    <div className="space-y-4">
                        {listings.length === 0 ? (
                            <Card variant="glass" className="p-12 text-center">
                                <Package size={48} className="mx-auto text-muted-foreground mb-4" />
                                <h3 className="text-xl font-semibold mb-2">No listings yet</h3>
                                <p className="text-muted-foreground mb-6">Start selling your unused items!</p>
                                <Link href="/sell">
                                    <Button variant="primary" icon={<PlusCircle size={18} />}>
                                        Create Listing
                                    </Button>
                                </Link>
                            </Card>
                        ) : (
                            listings.map((product) => (
                                <Card key={product._id} variant="glass" className="p-4">
                                    <div className="flex gap-4">
                                        <div className="w-20 h-20 rounded-lg overflow-hidden bg-muted flex-shrink-0">
                                            <img
                                                src={product.images[0] || `https://placehold.co/80x80/1a1a3a/6366f1?text=${product.category}`}
                                                alt={product.title}
                                                className="w-full h-full object-cover"
                                            />
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-start justify-between gap-2">
                                                <div>
                                                    <h3 className="font-medium line-clamp-1">{product.title}</h3>
                                                    <p className="text-lg font-bold text-emerald-500">Γé╣{product.price.toLocaleString()}</p>
                                                </div>
                                                <StatusBadge status={product.status} />
                                            </div>
                                            <div className="flex items-center gap-2 mt-3">
                                                <Link href={`/product/${product._id}`}>
                                                    <Button variant="ghost" size="sm" icon={<Eye size={16} />}>
                                                        View
                                                    </Button>
                                                </Link>
                                            </div>
                                        </div>
                                    </div>
                                </Card>
                            ))
                        )}
                    </div>
                )}

                {activeTab === "purchases" && (
                    <div className="space-y-4">
                        {purchases.length === 0 ? (
                            <Card variant="glass" className="p-12 text-center">
                                <ShoppingBag size={48} className="mx-auto text-muted-foreground mb-4" />
                                <h3 className="text-xl font-semibold mb-2">No purchases yet</h3>
                                <p className="text-muted-foreground mb-6">Start shopping from your campus community!</p>
                                <Link href="/browse">
                                    <Button variant="primary">Browse Products</Button>
                                </Link>
                            </Card>
                        ) : (
                            purchases.map((order) => (
                                <Card key={order._id} variant="glass" className="p-4">
                                    <div className="flex gap-4">
                                        <div className="w-20 h-20 rounded-lg overflow-hidden bg-muted flex-shrink-0">
                                            <img
                                                src={order.product.images?.[0] || "https://placehold.co/80x80/1a1a3a/6366f1"}
                                                alt={order.product.title}
                                                className="w-full h-full object-cover"
                                            />
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-start justify-between gap-2 mb-2">
                                                <div>
                                                    <h3 className="font-medium line-clamp-1">{order.product.title}</h3>
                                                    <p className="text-sm text-muted-foreground">from {order.seller?.name}</p>
                                                </div>
                                                <StatusBadge status={order.orderStatus} />
                                            </div>
                                            <div className="flex items-center justify-between">
                                                <div className="text-sm text-muted-foreground">
                                                    <span className="font-medium text-foreground">Γé╣{order.amount.toLocaleString()}</span>
                                                    {" ΓÇó "}
                                                    {order.deliveryLocation.name}
                                                </div>
                                                <div className="flex gap-2">
                                                    {order.orderStatus === "confirmed" && (
                                                        <Button
                                                            variant="primary"
                                                            size="sm"
                                                            icon={<CheckCircle size={16} />}
                                                            onClick={() => handleOrderAction(order._id, "delivered")}
                                                        >
                                                            Confirm Delivery
                                                        </Button>
                                                    )}
                                                    {(order.orderStatus === "placed" || order.orderStatus === "confirmed") && (
                                                        <Button
                                                            variant="ghost"
                                                            size="sm"
                                                            icon={<XCircle size={16} />}
                                                            onClick={() => handleOrderAction(order._id, "cancel")}
                                                        >
                                                            Cancel
                                                        </Button>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </Card>
                            ))
                        )}
                    </div>
                )}

                {activeTab === "sales" && (
                    <div className="space-y-4">
                        {sales.length === 0 ? (
                            <Card variant="glass" className="p-12 text-center">
                                <DollarSign size={48} className="mx-auto text-muted-foreground mb-4" />
                                <h3 className="text-xl font-semibold mb-2">No sales yet</h3>
                                <p className="text-muted-foreground mb-6">List your items to start selling!</p>
                                <Link href="/sell">
                                    <Button variant="primary" icon={<PlusCircle size={18} />}>
                                        Create Listing
                                    </Button>
                                </Link>
                            </Card>
                        ) : (
                            sales.map((order) => (
                                <Card key={order._id} variant="glass" className="p-4">
                                    <div className="flex gap-4">
                                        <div className="w-20 h-20 rounded-lg overflow-hidden bg-muted flex-shrink-0">
                                            <img
                                                src={order.product.images?.[0] || "https://placehold.co/80x80/1a1a3a/6366f1"}
                                                alt={order.product.title}
                                                className="w-full h-full object-cover"
                                            />
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-start justify-between gap-2 mb-2">
                                                <div>
                                                    <h3 className="font-medium line-clamp-1">{order.product.title}</h3>
                                                    <p className="text-sm text-muted-foreground">to {order.buyer?.name}</p>
                                                </div>
                                                <StatusBadge status={order.orderStatus} />
                                            </div>
                                            <div className="flex items-center justify-between">
                                                <div className="text-sm text-muted-foreground">
                                                    <span className="font-medium text-foreground">Γé╣{order.amount.toLocaleString()}</span>
                                                    {" ΓÇó "}
                                                    {order.deliveryLocation.name}
                                                </div>
                                                <div className="flex gap-2">
                                                    {order.orderStatus === "placed" && (
                                                        <Button
                                                            variant="primary"
                                                            size="sm"
                                                            icon={<Truck size={16} />}
                                                            onClick={() => handleOrderAction(order._id, "confirm")}
                                                        >
                                                            Confirm Order
                                                        </Button>
                                                    )}
                                                    {order.orderStatus === "placed" && (
                                                        <Button
                                                            variant="ghost"
                                                            size="sm"
                                                            icon={<XCircle size={16} />}
                                                            onClick={() => handleOrderAction(order._id, "cancel")}
                                                        >
                                                            Cancel
                                                        </Button>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </Card>
                            ))
                        )}
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Card } from "@/components/ui/Card";
import { Mail, Lock, ShoppingBag } from "lucide-react";

export default function LoginPage() {
    const router = useRouter();
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        try {
            const res = await fetch("/api/auth/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ email, password }),
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Login failed");
            }

            localStorage.setItem("token", data.access);
            localStorage.setItem("refreshToken", data.refresh);
            localStorage.setItem("user", JSON.stringify(data.user));

            router.push("/dashboard");
        } catch (err: unknown) {
            setError(err instanceof Error ? err.message : "Login failed");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-[calc(100vh-4rem)] flex items-center justify-center py-12 px-4">
            {/* Background decoration */}
            <div className="absolute inset-0 hero-gradient pointer-events-none" />
            <div className="floating-shape w-96 h-96 bg-indigo-500/20 top-20 -left-48" />
            <div className="floating-shape w-64 h-64 bg-rose-500/20 bottom-20 right-20" style={{ animationDelay: "-3s" }} />

            <Card variant="glass" className="relative w-full max-w-md p-8">
                {/* Logo */}
                <div className="text-center mb-8">
                    <div className="w-16 h-16 mx-auto rounded-2xl bg-gradient-to-br from-indigo-500 to-violet-500 flex items-center justify-center mb-4">
                        <ShoppingBag size={32} className="text-white" />
                    </div>
                    <h1 className="text-2xl font-bold">Welcome Back</h1>
                    <p className="text-muted-foreground mt-1">Sign in to your account</p>
                </div>

                {/* Error */}
                {error && (
                    <div className="mb-6 p-4 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive text-sm">
                        {error}
                    </div>
                )}

                {/* Form */}
                <form onSubmit={handleSubmit} className="space-y-4">
                    <Input
                        label="Email"
                        type="email"
                        placeholder="you@college.edu"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        icon={<Mail size={18} />}
                        required
                    />

                    <Input
                        label="Password"
                        type="password"
                        placeholder="Enter your password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        icon={<Lock size={18} />}
                        required
                    />

                    <div className="flex items-center justify-between text-sm">
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input type="checkbox" className="rounded border-border" />
                            <span className="text-muted-foreground">Remember me</span>
                        </label>
                        <Link href="/forgot-password" className="text-primary hover:underline">
                            Forgot password?
                        </Link>
                    </div>

                    <Button
                        type="submit"
                        variant="primary"
                        className="w-full"
                        loading={loading}
                    >
                        Sign In
                    </Button>
                </form>

                {/* Register link */}
                <p className="text-center text-muted-foreground mt-6">
                    Don't have an account?{" "}
                    <Link href="/register" className="text-primary font-medium hover:underline">
                        Sign up
                    </Link>
                </p>
            </Card>
        </div>
    );
}

"use client";

import React, { useEffect, useState, use } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Button } from "@/components/ui/Button";
import { Card } from "@/components/ui/Card";
import { Avatar } from "@/components/ui/Avatar";
import { ConditionBadge, StatusBadge } from "@/components/ui/Badge";
import {
    ArrowLeft,
    Heart,
    Share2,
    MapPin,
    Calendar,
    MessageCircle,
    ShieldCheck,
    ChevronLeft,
    ChevronRight,
    AlertTriangle,
    Clock
} from "lucide-react";

interface Product {
    _id: string;
    title: string;
    description: string;
    price: number;
    images: string[];
    condition: string;
    status: string;
    category: string;
    seller: {
        _id: string;
        name: string;
        profileImage?: string;
        bio?: string;
        createdAt: string;
    };
    college: {
        _id: string;
        name: string;
        shortCode: string;
        city: string;
        deliveryLocations: { name: string; building: string }[];
    };
    availableDays?: string[];
    availableTimeStart?: string;
    availableTimeEnd?: string;
    availableNote?: string;
    createdAt: string;
}

const categoryIcons: Record<string, string> = {
    books: "≡ƒôÜ",
    electronics: "≡ƒÆ╗",
    clothing: "≡ƒæò",
    furniture: "≡ƒ¬æ",
    sports: "ΓÜ╜",
    stationery: "Γ£Å∩╕Å",
    accessories: "≡ƒæ£",
    other: "≡ƒôª",
};

export default function ProductPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params);
    const router = useRouter();
    const [product, setProduct] = useState<Product | null>(null);
    const [loading, setLoading] = useState(true);
    const [currentImage, setCurrentImage] = useState(0);
    const [isOwner, setIsOwner] = useState(false);

    useEffect(() => {
        const fetchProduct = async () => {
            try {
                const res = await fetch(`/api/products/${id}`);
                const data = await res.json();

                if (data.product) {
                    setProduct(data.product);

                    // Check if current user is owner
                    const user = localStorage.getItem("user");
                    if (user) {
                        const userData = JSON.parse(user);
                        setIsOwner(userData.id === data.product.seller._id);
                    }
                }
            } catch (error) {
                console.error("Error fetching product:", error);
            } finally {
                setLoading(false);
            }
        };

        fetchProduct();
    }, [id]);

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin" />
            </div>
        );
    }

    if (!product) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Card variant="glass" className="p-12 text-center">
                    <AlertTriangle size={48} className="mx-auto text-warning mb-4" />
                    <h2 className="text-xl font-semibold mb-2">Product Not Found</h2>
                    <p className="text-muted-foreground mb-6">This product may have been removed or sold.</p>
                    <Link href="/browse">
                        <Button variant="primary">Browse Products</Button>
                    </Link>
                </Card>
            </div>
        );
    }

    const defaultImage = `https://placehold.co/800x600/1a1a3a/6366f1?text=${encodeURIComponent(product.category)}`;
    const images = product.images.length > 0 ? product.images : [defaultImage];

    const memberSince = new Date(product.seller.createdAt).toLocaleDateString("en-US", {
        month: "short",
        year: "numeric",
    });
    const listedDate = new Date(product.createdAt).toLocaleDateString("en-US", {
        month: "short",
        day: "numeric",
    });

    return (
        <div className="min-h-screen py-4 sm:py-8 pb-24 sm:pb-8">
            <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
                {/* Back button */}
                <Link href="/browse" className="inline-flex items-center gap-2 text-xs sm:text-sm text-muted-foreground hover:text-foreground mb-4 sm:mb-6 transition-colors">
                    <ArrowLeft size={16} className="sm:w-5 sm:h-5" />
                    Back to browse
                </Link>

                <div className="grid lg:grid-cols-2 gap-8">
                    {/* Image gallery */}
                    <div className="space-y-4">
                        <Card variant="glass" className="relative aspect-[4/3] overflow-hidden">
                            <img
                                src={images[currentImage]}
                                alt={product.title}
                                className="w-full h-full object-cover"
                            />

                            {/* Status overlay */}
                            {product.status !== "available" && (
                                <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                                    <StatusBadge status={product.status} />
                                </div>
                            )}

                            {/* Navigation arrows */}
                            {images.length > 1 && (
                                <>
                                    <button
                                        onClick={() => setCurrentImage((currentImage - 1 + images.length) % images.length)}
                                        className="absolute left-4 top-1/2 -translate-y-1/2 p-2 rounded-full bg-black/50 hover:bg-black/70 transition-colors"
                                    >
                                        <ChevronLeft size={24} className="text-white" />
                                    </button>
                                    <button
                                        onClick={() => setCurrentImage((currentImage + 1) % images.length)}
                                        className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-full bg-black/50 hover:bg-black/70 transition-colors"
                                    >
                                        <ChevronRight size={24} className="text-white" />
                                    </button>
                                </>
                            )}

                            {/* Category icon */}
                            <div className="absolute top-4 left-4 text-3xl filter drop-shadow-lg">
                                {categoryIcons[product.category] || categoryIcons.other}
                            </div>
                        </Card>

                        {/* Thumbnails */}
                        {images.length > 1 && (
                            <div className="flex gap-2 overflow-x-auto pb-2">
                                {images.map((img, index) => (
                                    <button
                                        key={index}
                                        onClick={() => setCurrentImage(index)}
                                        className={`w-16 h-16 rounded-lg overflow-hidden flex-shrink-0 ring-2 transition-all ${currentImage === index ? "ring-primary" : "ring-transparent"
                                            }`}
                                    >
                                        <img src={img} alt="" className="w-full h-full object-cover" />
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Product details */}
                    <div className="space-y-6">
                        {/* Header */}
                        <div>
                            <div className="flex items-center gap-2 text-[10px] sm:text-xs text-muted-foreground mb-1 sm:mb-2 text-wrap">
                                <span className="text-indigo-400 font-medium">{product.college.shortCode}</span>
                                <span>ΓÇó</span>
                                <span className="capitalize">{product.category}</span>
                                <span>ΓÇó</span>
                                <span>Listed {listedDate}</span>
                            </div>
                            <h1 className="text-xl sm:text-2xl lg:text-3xl font-bold mb-2 sm:mb-3">{product.title}</h1>
                            <div className="flex items-center gap-3">
                                <span className="text-2xl sm:text-3xl font-bold text-emerald-500">
                                    Γé╣{product.price.toLocaleString()}
                                </span>
                                <ConditionBadge condition={product.condition} size="sm" />
                            </div>
                        </div>

                        {/* Actions (Desktop) */}
                        <div className="hidden sm:flex gap-3">
                            {product.status === "available" && !isOwner && (
                                <Link href={`/checkout/${product._id}`} className="flex-1">
                                    <Button variant="primary" className="w-full" size="lg">
                                        Buy Now
                                    </Button>
                                </Link>
                            )}
                            {isOwner && (
                                <Link href={`/dashboard`} className="flex-1">
                                    <Button variant="outline" className="w-full" size="lg">
                                        Manage Listing
                                    </Button>
                                </Link>
                            )}
                            <Button variant="outline" size="lg" icon={<Heart size={20} />}>
                                Save
                            </Button>
                            <Button variant="outline" size="lg" icon={<Share2 size={20} />}>
                                Share
                            </Button>
                        </div>

                        {/* Escrow info */}
                        <Card variant="gradient" className="p-4">
                            <div className="flex items-start gap-3">
                                <ShieldCheck size={24} className="text-emerald-500 flex-shrink-0 mt-0.5" />
                                <div>
                                    <h3 className="font-semibold text-sm">Secure Escrow Payment</h3>
                                    <p className="text-sm text-muted-foreground">
                                        Your payment is held safely until you confirm delivery. No COD.
                                    </p>
                                </div>
                            </div>
                        </Card>

                        {/* Description */}
                        <div>
                            <h2 className="font-semibold mb-2">Description</h2>
                            <p className="text-muted-foreground whitespace-pre-line">
                                {product.description}
                            </p>
                        </div>

                        {/* Location */}
                        <div>
                            <h2 className="font-semibold mb-2">Pickup Locations</h2>
                            <Card variant="glass" className="p-4">
                                <div className="flex items-center gap-2 mb-3">
                                    <MapPin size={18} className="text-primary" />
                                    <span className="font-medium">{product.college.name}</span>
                                    <span className="text-muted-foreground">ΓÇó {product.college.city}</span>
                                </div>
                                <div className="flex flex-wrap gap-2">
                                    {product.college.deliveryLocations?.map((loc, index) => (
                                        <span key={index} className="px-3 py-1 rounded-full bg-muted text-sm">
                                            {loc.name}
                                        </span>
                                    ))}
                                    {(!product.college.deliveryLocations || product.college.deliveryLocations.length === 0) && (
                                        <span className="text-sm text-muted-foreground">
                                            Contact seller for pickup location
                                        </span>
                                    )}
                                </div>
                            </Card>
                        </div>

                        {/* Seller Availability */}
                        {product.availableDays && product.availableDays.length > 0 && (
                            <Card variant="glass" className="p-4">
                                <h2 className="font-semibold mb-3 flex items-center gap-2">
                                    <Clock size={18} className="text-primary" />
                                    Seller Availability
                                </h2>
                                <div className="space-y-2">
                                    <div className="flex flex-wrap gap-2">
                                        {product.availableDays.map((day) => (
                                            <span key={day} className="px-3 py-1 rounded-full bg-primary/20 text-primary text-sm capitalize">
                                                {day}
                                            </span>
                                        ))}
                                    </div>
                                    {product.availableTimeStart && product.availableTimeEnd && (
                                        <p className="text-sm text-muted-foreground">
                                            {product.availableTimeStart} - {product.availableTimeEnd}
                                        </p>
                                    )}
                                    {product.availableNote && (
                                        <p className="text-sm text-muted-foreground italic">
                                            "{product.availableNote}"
                                        </p>
                                    )}
                                </div>
                            </Card>
                        )}

                        {/* Seller info */}
                        <Card variant="glass" className="p-4">
                            <h2 className="font-semibold mb-3">Seller</h2>
                            <div className="flex items-center gap-3">
                                <Avatar
                                    src={product.seller.profileImage}
                                    name={product.seller.name}
                                    size="lg"
                                />
                                <div className="flex-1">
                                    <p className="font-medium">{product.seller.name}</p>
                                    <p className="text-sm text-muted-foreground flex items-center gap-1">
                                        <Calendar size={14} />
                                        Member since {memberSince}
                                    </p>
                                </div>
                                {!isOwner && (
                                    <Button variant="outline" size="sm" icon={<MessageCircle size={16} />}>
                                        Contact
                                    </Button>
                                )}
                            </div>
                            {product.seller.bio && (
                                <p className="mt-3 text-sm text-muted-foreground">{product.seller.bio}</p>
                            )}
                        </Card>
                    </div>
                </div>
            </div>

            {/* Sticky Mobile Buy Bar */}
            {!isOwner && product.status === "available" && (
                <div className="fixed bottom-0 left-0 right-0 bg-background/80 backdrop-blur-xl border-t border-border p-4 z-40 sm:hidden animate-in slide-in-from-bottom" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom) + 16px)' }}>
                    <div className="flex items-center justify-between gap-4 max-w-6xl mx-auto">
                        <div className="flex flex-col">
                            <span className="text-[10px] uppercase font-bold text-muted-foreground tracking-wider leading-none mb-1">Total Price</span>
                            <span className="text-xl font-bold text-emerald-500 leading-none">Γé╣{product.price.toLocaleString()}</span>
                        </div>
                        <div className="flex gap-2 flex-grow max-w-[200px]">
                            <Button variant="outline" size="md" className="p-3" icon={<Heart size={18} />} />
                            <Link href={`/checkout/${product._id}`} className="flex-1">
                                <Button variant="primary" size="md" className="w-full py-2.5 font-bold">
                                    Buy Now
                                </Button>
                            </Link>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Card } from "@/components/ui/Card";
import { Avatar } from "@/components/ui/Avatar";
import { OTPModal } from "@/components/ui/OTPModal";
import {
    ArrowLeft,
    User,
    Mail,
    Phone,
    GraduationCap,
    Edit3,
    Save,
    X,
    Shield,
    CheckCircle,
    Wallet
} from "lucide-react";

interface UserProfile {
    id: string;
    name: string;
    email: string;
    phone?: string;
    bio?: string;
    profileImage?: string;
    college?: {
        _id: string;
        name: string;
        shortCode: string;
    };
    wallet: number;
    createdAt: string;
}

export default function ProfilePage() {
    const router = useRouter();
    const [user, setUser] = useState<UserProfile | null>(null);
    const [loading, setLoading] = useState(true);
    const [editing, setEditing] = useState(false);
    const [saving, setSaving] = useState(false);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState("");

    // OTP state
    const [showOTPModal, setShowOTPModal] = useState(false);
    const [otpPurpose, setOtpPurpose] = useState<"profile_update" | "email_change">("profile_update");
    const [otpEmail, setOtpEmail] = useState("");
    const [otpError, setOtpError] = useState("");
    const [otpLoading, setOtpLoading] = useState(false);

    const [formData, setFormData] = useState({
        name: "",
        email: "",
        phone: "",
        bio: "",
    });

    useEffect(() => {
        const token = localStorage.getItem("token");
        if (!token) {
            router.push("/login?redirect=/profile");
            return;
        }
        fetchProfile();
    }, [router]);

    const fetchProfile = async () => {
        try {
            const token = localStorage.getItem("token");
            const res = await fetch("/api/user/profile", {
                headers: { Authorization: `Bearer ${token}` },
            });

            if (!res.ok) {
                throw new Error("Failed to fetch profile");
            }

            const data = await res.json();
            setUser(data.user);
            setFormData({
                name: data.user.name || "",
                email: data.user.email || "",
                phone: data.user.phone || "",
                bio: data.user.bio || "",
            });
        } catch (error) {
            console.error("Error fetching profile:", error);
            router.push("/login");
        } finally {
            setLoading(false);
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    // Check if email is being changed
    const isEmailChanging = user && formData.email.toLowerCase() !== user.email.toLowerCase();

    // Send OTP and show modal
    const handleSave = async () => {
        setSaving(true);
        setError("");

        try {
            const token = localStorage.getItem("token");

            // Determine purpose and target email
            const purpose = isEmailChanging ? "email_change" : "profile_update";
            const targetEmail = isEmailChanging ? formData.email : user?.email;

            // Send OTP
            const res = await fetch("/api/otp/send", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${token}`,
                },
                body: JSON.stringify({
                    purpose,
                    email: isEmailChanging ? formData.email : undefined
                }),
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Failed to send OTP");
            }

            // Show OTP modal
            setOtpPurpose(purpose);
            setOtpEmail(data.email || targetEmail || "");
            setOtpError("");
            setShowOTPModal(true);
        } catch (err) {
            setError(err instanceof Error ? err.message : "Failed to send OTP");
        } finally {
            setSaving(false);
        }
    };

    // Verify OTP and update profile
    const handleVerifyOTP = async (otp: string) => {
        setOtpLoading(true);
        setOtpError("");

        try {
            const token = localStorage.getItem("token");

            const body: Record<string, unknown> = {
                otp,
                purpose: otpPurpose,
            };

            if (otpPurpose === "email_change") {
                body.email = formData.email;
            } else {
                body.profileData = {
                    name: formData.name,
                    phone: formData.phone,
                    bio: formData.bio,
                };
            }

            const res = await fetch("/api/otp/verify", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${token}`,
                },
                body: JSON.stringify(body),
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Failed to verify OTP");
            }

            // Success!
            setShowOTPModal(false);
            setEditing(false);
            setSuccess(true);

            // Refresh profile
            await fetchProfile();

            // Update local storage
            if (data.user) {
                const storedUser = JSON.parse(localStorage.getItem("user") || "{}");
                localStorage.setItem("user", JSON.stringify({
                    ...storedUser,
                    name: data.user.name,
                    email: data.user.email,
                }));
            }

            setTimeout(() => setSuccess(false), 3000);
        } catch (err) {
            setOtpError(err instanceof Error ? err.message : "Failed to verify");
        } finally {
            setOtpLoading(false);
        }
    };

    // Resend OTP
    const handleResendOTP = async () => {
        const token = localStorage.getItem("token");

        const res = await fetch("/api/otp/send", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify({
                purpose: otpPurpose,
                email: otpPurpose === "email_change" ? formData.email : undefined,
            }),
        });

        const data = await res.json();
        if (!res.ok) {
            setOtpError(data.error || "Failed to resend OTP");
        }
    };

    const handleCancel = () => {
        setEditing(false);
        if (user) {
            setFormData({
                name: user.name || "",
                email: user.email || "",
                phone: user.phone || "",
                bio: user.bio || "",
            });
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <div className="animate-spin h-8 w-8 border-2 border-primary border-t-transparent rounded-full" />
            </div>
        );
    }

    if (!user) return null;

    const memberSince = new Date(user.createdAt).toLocaleDateString("en-US", {
        month: "long",
        year: "numeric",
    });

    return (
        <div className="min-h-screen py-8">
            <div className="max-w-2xl mx-auto px-4 sm:px-6">
                {/* Header */}
                <div className="flex items-center gap-4 mb-8">
                    <button
                        onClick={() => router.back()}
                        className="p-2 rounded-full hover:bg-muted transition-colors"
                    >
                        <ArrowLeft size={24} />
                    </button>
                    <h1 className="text-2xl font-bold">Profile</h1>
                </div>

                {/* Success message */}
                {success && (
                    <div className="mb-6 p-4 rounded-lg bg-emerald-500/10 border border-emerald-500/20 flex items-center gap-3">
                        <CheckCircle size={20} className="text-emerald-500" />
                        <span className="text-emerald-400">Profile updated successfully!</span>
                    </div>
                )}

                {/* Error message */}
                {error && (
                    <div className="mb-6 p-4 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive">
                        {error}
                    </div>
                )}

                {/* Profile Card */}
                <Card variant="glass" className="p-6 mb-6">
                    {/* Avatar and basic info */}
                    <div className="flex items-start gap-6 mb-6">
                        <Avatar
                            src={user.profileImage}
                            name={user.name}
                            size="xl"
                        />
                        <div className="flex-1">
                            <h2 className="text-xl font-bold">{user.name}</h2>
                            <p className="text-muted-foreground">{user.email}</p>
                            <p className="text-sm text-muted-foreground mt-1">
                                Member since {memberSince}
                            </p>
                        </div>
                        {!editing && (
                            <Button
                                variant="outline"
                                size="sm"
                                icon={<Edit3 size={16} />}
                                onClick={() => setEditing(true)}
                            >
                                Edit
                            </Button>
                        )}
                    </div>

                    {/* Editable fields */}
                    <div className="space-y-4">
                        {editing ? (
                            <>
                                <Input
                                    label="Full Name"
                                    name="name"
                                    value={formData.name}
                                    onChange={handleChange}
                                    icon={<User size={18} />}
                                    required
                                />

                                <Input
                                    label="Email"
                                    name="email"
                                    type="email"
                                    value={formData.email}
                                    onChange={handleChange}
                                    icon={<Mail size={18} />}
                                    required
                                />

                                <Input
                                    label="Phone Number"
                                    name="phone"
                                    type="tel"
                                    value={formData.phone}
                                    onChange={handleChange}
                                    icon={<Phone size={18} />}
                                    placeholder="+91 9876543210"
                                />

                                <div>
                                    <label className="block text-sm font-medium mb-2">Bio</label>
                                    <textarea
                                        name="bio"
                                        value={formData.bio}
                                        onChange={handleChange}
                                        className="w-full bg-input border border-border rounded-lg px-4 py-3 focus:outline-none focus:border-primary min-h-[100px] resize-none"
                                        placeholder="Tell others about yourself..."
                                        maxLength={500}
                                    />
                                    <p className="text-xs text-muted-foreground mt-1">
                                        {formData.bio.length}/500 characters
                                    </p>
                                </div>

                                <div className="flex gap-3 pt-4">
                                    <Button
                                        variant="primary"
                                        icon={<Save size={18} />}
                                        onClick={handleSave}
                                        loading={saving}
                                    >
                                        Save Changes
                                    </Button>
                                    <Button
                                        variant="outline"
                                        icon={<X size={18} />}
                                        onClick={handleCancel}
                                    >
                                        Cancel
                                    </Button>
                                </div>
                            </>
                        ) : (
                            <>
                                <div className="flex items-center gap-3 p-3 rounded-lg bg-muted/30">
                                    <Mail size={18} className="text-muted-foreground" />
                                    <div>
                                        <p className="text-xs text-muted-foreground">Email</p>
                                        <p>{user.email}</p>
                                    </div>
                                </div>

                                <div className="flex items-center gap-3 p-3 rounded-lg bg-muted/30">
                                    <Phone size={18} className="text-muted-foreground" />
                                    <div>
                                        <p className="text-xs text-muted-foreground">Phone</p>
                                        <p>{user.phone || "Not set"}</p>
                                    </div>
                                </div>

                                {user.college && (
                                    <div className="flex items-center gap-3 p-3 rounded-lg bg-muted/30">
                                        <GraduationCap size={18} className="text-muted-foreground" />
                                        <div>
                                            <p className="text-xs text-muted-foreground">College</p>
                                            <p>{user.college.name} ({user.college.shortCode})</p>
                                        </div>
                                    </div>
                                )}

                                {user.bio && (
                                    <div className="p-3 rounded-lg bg-muted/30">
                                        <p className="text-xs text-muted-foreground mb-1">Bio</p>
                                        <p className="text-sm">{user.bio}</p>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </Card>

                {/* Wallet Card */}
                <Link href="/wallet">
                    <Card variant="gradient" className="p-6 mb-6 cursor-pointer hover:scale-[1.02] transition-transform">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="w-12 h-12 rounded-full bg-emerald-500/20 flex items-center justify-center">
                                    <Wallet size={24} className="text-emerald-500" />
                                </div>
                                <div>
                                    <p className="text-sm text-muted-foreground">Wallet Balance</p>
                                    <p className="text-2xl font-bold text-emerald-500">
                                        Γé╣{user.wallet?.toLocaleString() || "0"}
                                    </p>
                                </div>
                            </div>
                            <ArrowLeft size={20} className="rotate-180 text-muted-foreground" />
                        </div>
                        <p className="text-xs text-muted-foreground mt-4">
                            Tap to manage your wallet and request withdrawals
                        </p>
                    </Card>
                </Link>

                {/* Security Card */}
                <Card variant="glass" className="p-6">
                    <div className="flex items-center gap-2 mb-4">
                        <Shield size={20} className="text-primary" />
                        <h3 className="font-semibold">Account Security</h3>
                    </div>

                    <div className="space-y-3">
                        <div className="flex items-center justify-between p-3 rounded-lg bg-muted/30">
                            <span className="text-sm">Password</span>
                            <Button variant="outline" size="sm" disabled>
                                Change Password
                            </Button>
                        </div>

                        <div className="flex items-center justify-between p-3 rounded-lg bg-muted/30">
                            <span className="text-sm">Two-Factor Auth</span>
                            <span className="text-xs text-muted-foreground">Coming soon</span>
                        </div>
                    </div>
                </Card>

                {/* Quick Links */}
                <div className="mt-8 flex gap-4 justify-center">
                    <Link href="/dashboard">
                        <Button variant="outline">Dashboard</Button>
                    </Link>
                    <Link href="/sell">
                        <Button variant="primary">Sell Something</Button>
                    </Link>
                </div>
            </div>

            {/* OTP Verification Modal */}
            <OTPModal
                isOpen={showOTPModal}
                onClose={() => setShowOTPModal(false)}
                onVerify={handleVerifyOTP}
                onResend={handleResendOTP}
                email={otpEmail}
                purpose={otpPurpose}
                loading={otpLoading}
                error={otpError}
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Select } from "@/components/ui/Select";
import { Card } from "@/components/ui/Card";
import { Mail, Lock, User, Phone, ShoppingBag, GraduationCap } from "lucide-react";

interface College {
    _id: string;
    name: string;
    shortCode: string;
}

export default function RegisterPage() {
    const router = useRouter();
    const [colleges, setColleges] = useState<College[]>([]);
    const [formData, setFormData] = useState({
        name: "",
        email: "",
        password: "",
        confirmPassword: "",
        phone: "",
        college: "",
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    useEffect(() => {
        fetch("/api/colleges")
            .then((res) => res.json())
            .then((data) => setColleges(data.colleges || []))
            .catch(console.error);
    }, []);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        if (formData.password !== formData.confirmPassword) {
            setError("Passwords do not match");
            setLoading(false);
            return;
        }

        if (formData.password.length < 6) {
            setError("Password must be at least 6 characters");
            setLoading(false);
            return;
        }

        try {
            const res = await fetch("/api/auth/signup", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    name: formData.name,
                    email: formData.email,
                    password: formData.password,
                    phone: formData.phone,
                    college: formData.college || undefined,
                }),
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Registration failed");
            }

            localStorage.setItem("token", data.access);
            localStorage.setItem("refreshToken", data.refresh);
            localStorage.setItem("user", JSON.stringify(data.user));

            router.push("/dashboard");
        } catch (err: unknown) {
            setError(err instanceof Error ? err.message : "Registration failed");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-[calc(100vh-4rem)] flex items-center justify-center py-12 px-4">
            {/* Background decoration */}
            <div className="absolute inset-0 hero-gradient pointer-events-none" />
            <div className="floating-shape w-96 h-96 bg-violet-500/20 top-20 -right-48" />
            <div className="floating-shape w-64 h-64 bg-indigo-500/20 bottom-20 left-20" style={{ animationDelay: "-3s" }} />

            <Card variant="glass" className="relative w-full max-w-md p-8">
                {/* Logo */}
                <div className="text-center mb-8">
                    <div className="w-16 h-16 mx-auto rounded-2xl bg-gradient-to-br from-indigo-500 to-violet-500 flex items-center justify-center mb-4">
                        <ShoppingBag size={32} className="text-white" />
                    </div>
                    <h1 className="text-2xl font-bold">Create Account</h1>
                    <p className="text-muted-foreground mt-1">Join your campus community</p>
                </div>

                {/* Error */}
                {error && (
                    <div className="mb-6 p-4 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive text-sm">
                        {error}
                    </div>
                )}

                {/* Form */}
                <form onSubmit={handleSubmit} className="space-y-4">
                    <Input
                        label="Full Name"
                        name="name"
                        type="text"
                        placeholder="John Doe"
                        value={formData.name}
                        onChange={handleChange}
                        icon={<User size={18} />}
                        required
                    />

                    <Input
                        label="Email"
                        name="email"
                        type="email"
                        placeholder="you@college.edu"
                        value={formData.email}
                        onChange={handleChange}
                        icon={<Mail size={18} />}
                        required
                    />

                    <Input
                        label="Phone Number"
                        name="phone"
                        type="tel"
                        placeholder="+91 9876543210"
                        value={formData.phone}
                        onChange={handleChange}
                        icon={<Phone size={18} />}
                        required
                    />

                    <Select
                        label="College"
                        name="college"
                        value={formData.college}
                        onChange={handleChange}
                        options={[
                            { value: "", label: "Select your college" },
                            ...colleges.map(c => ({ value: c._id, label: `${c.name} (${c.shortCode})` }))
                        ]}
                    />

                    <Input
                        label="Password"
                        name="password"
                        type="password"
                        placeholder="At least 6 characters"
                        value={formData.password}
                        onChange={handleChange}
                        icon={<Lock size={18} />}
                        required
                    />

                    <Input
                        label="Confirm Password"
                        name="confirmPassword"
                        type="password"
                        placeholder="Confirm your password"
                        value={formData.confirmPassword}
                        onChange={handleChange}
                        icon={<Lock size={18} />}
                        required
                    />

                    <div className="flex items-start gap-2 text-sm">
                        <input type="checkbox" id="terms" className="mt-1 rounded border-border" required />
                        <label htmlFor="terms" className="text-muted-foreground">
                            I agree to the{" "}
                            <Link href="/terms" className="text-primary hover:underline">Terms of Service</Link>
                            {" "}and{" "}
                            <Link href="/privacy" className="text-primary hover:underline">Privacy Policy</Link>
                        </label>
                    </div>

                    <Button
                        type="submit"
                        variant="primary"
                        className="w-full"
                        loading={loading}
                    >
                        Create Account
                    </Button>
                </form>

                {/* Divider */}
                <div className="flex items-center gap-4 my-6">
                    <div className="flex-1 h-px bg-border" />
                    <span className="text-muted-foreground text-sm">or</span>
                    <div className="flex-1 h-px bg-border" />
                </div>

                {/* Social login */}
                <Button variant="outline" className="w-full">
                    <svg className="w-5 h-5" viewBox="0 0 24 24">
                        <path fill="currentColor" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                        <path fill="currentColor" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                        <path fill="currentColor" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
                        <path fill="currentColor" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                    </svg>
                    Continue with Google
                </Button>

                {/* Login link */}
                <p className="text-center text-muted-foreground mt-6">
                    Already have an account?{" "}
                    <Link href="/login" className="text-primary font-medium hover:underline">
                        Sign in
                    </Link>
                </p>
            </Card>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Select } from "@/components/ui/Select";
import { Card } from "@/components/ui/Card";
import {
    Camera,
    X,
    Package,
    DollarSign,
    FileText,
    Tag,
    Sparkles,
    ArrowRight,
    ArrowLeft,
    Check,
    Clock,
    Calendar,
    AlertCircle
} from "lucide-react";

const categories = [
    { value: "books", label: "≡ƒôÜ Books & Textbooks" },
    { value: "electronics", label: "≡ƒÆ╗ Electronics" },
    { value: "clothing", label: "≡ƒæò Clothing & Accessories" },
    { value: "furniture", label: "≡ƒ¬æ Furniture" },
    { value: "sports", label: "ΓÜ╜ Sports & Fitness" },
    { value: "stationery", label: "Γ£Å∩╕Å Stationery" },
    { value: "accessories", label: "≡ƒæ£ Bags & Accessories" },
    { value: "other", label: "≡ƒôª Other" },
];

const conditions = [
    { value: "new", label: "New - Never used, with tags" },
    { value: "like-new", label: "Like New - Used once or twice" },
    { value: "good", label: "Good - Some signs of use" },
    { value: "fair", label: "Fair - Visible wear but works fine" },
];

const weekdays = [
    { value: "monday", label: "Mon" },
    { value: "tuesday", label: "Tue" },
    { value: "wednesday", label: "Wed" },
    { value: "thursday", label: "Thu" },
    { value: "friday", label: "Fri" },
    { value: "saturday", label: "Sat" },
    { value: "sunday", label: "Sun" },
];

interface College {
    _id: string;
    name: string;
    shortCode: string;
}

export default function SellPage() {
    const router = useRouter();
    const [step, setStep] = useState(1);
    const [loading, setLoading] = useState(false);
    const [colleges, setColleges] = useState<College[]>([]);
    const [images, setImages] = useState<string[]>([]);

    const [formData, setFormData] = useState({
        title: "",
        description: "",
        category: "",
        condition: "",
        price: "",
        college: "",
        availableDays: [] as string[],
        availableTimeStart: "",
        availableTimeEnd: "",
        availableNote: "",
    });

    useEffect(() => {
        const token = localStorage.getItem("token");
        if (!token) {
            router.push("/login?redirect=/sell");
            return;
        }

        fetch("/api/colleges")
            .then((res) => res.json())
            .then((data) => setColleges(data.colleges || []))
            .catch(console.error);

        const user = localStorage.getItem("user");
        if (user) {
            const userData = JSON.parse(user);
            if (userData.college?._id) {
                setFormData(prev => ({ ...prev, college: userData.college._id }));
            }
        }
    }, [router]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const toggleDay = (day: string) => {
        setFormData(prev => ({
            ...prev,
            availableDays: prev.availableDays.includes(day)
                ? prev.availableDays.filter(d => d !== day)
                : [...prev.availableDays, day]
        }));
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files) return;

        Array.from(files).forEach((file) => {
            const reader = new FileReader();
            reader.onload = () => {
                if (reader.result && images.length < 5) {
                    setImages(prev => [...prev, reader.result as string]);
                }
            };
            reader.readAsDataURL(file);
        });
    };

    const removeImage = (index: number) => {
        setImages(images.filter((_, i) => i !== index));
    };

    const handleSubmit = async () => {
        setLoading(true);

        try {
            const token = localStorage.getItem("token");
            const res = await fetch("/api/products", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${token}`,
                },
                body: JSON.stringify({
                    ...formData,
                    price: parseFloat(formData.price),
                    images,
                }),
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Failed to create listing");
            }

            router.push(`/product/${data.product._id}?created=true`);
        } catch (error) {
            console.error("Error creating listing:", error);
            alert("Failed to create listing. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    const canProceed = () => {
        switch (step) {
            case 1: return formData.category && formData.condition;
            case 2: return formData.title && formData.description && formData.price;
            case 3: return formData.availableDays.length > 0 && formData.availableTimeStart && formData.availableTimeEnd;
            case 4: return formData.college;
            default: return false;
        }
    };

    return (
        <div className="min-h-screen py-8">
            <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
                {/* Header */}
                <div className="text-center mb-8">
                    <h1 className="text-3xl sm:text-4xl font-bold mb-2">Sell Your Item</h1>
                    <p className="text-muted-foreground">
                        List your item in just a few steps
                    </p>
                </div>

                {/* Progress steps */}
                <div className="flex items-center justify-center gap-3 mb-12">
                    {[1, 2, 3, 4].map((s, index) => (
                        <React.Fragment key={s}>
                            <button
                                onClick={() => s < step && setStep(s)}
                                className={`w-10 h-10 rounded-full flex items-center justify-center font-semibold transition-all ${s === step
                                    ? "bg-gradient-to-r from-indigo-500 to-violet-500 text-white glow"
                                    : s < step
                                        ? "bg-emerald-500 text-white"
                                        : "bg-muted text-muted-foreground"
                                    }`}
                            >
                                {s < step ? <Check size={18} /> : s}
                            </button>
                            {index < 3 && (
                                <div className={`w-12 sm:w-16 h-1 rounded-full ${s < step ? "bg-emerald-500" : "bg-muted"}`} />
                            )}
                        </React.Fragment>
                    ))}
                </div>

                <Card variant="glass" className="p-6 sm:p-8">
                    {/* Step 1: Category & Condition */}
                    {step === 1 && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
                            <div className="text-center mb-8">
                                <div className="w-16 h-16 mx-auto rounded-2xl bg-gradient-to-br from-indigo-500 to-violet-500 flex items-center justify-center mb-4">
                                    <Tag size={32} className="text-white" />
                                </div>
                                <h2 className="text-xl font-semibold">What are you selling?</h2>
                                <p className="text-muted-foreground mt-1">Select a category and condition</p>
                            </div>

                            <Select
                                label="Category"
                                name="category"
                                value={formData.category}
                                onChange={handleChange}
                                options={[{ value: "", label: "Select a category" }, ...categories]}
                            />

                            <Select
                                label="Condition"
                                name="condition"
                                value={formData.condition}
                                onChange={handleChange}
                                options={[{ value: "", label: "Select condition" }, ...conditions]}
                            />
                        </div>
                    )}

                    {/* Step 2: Details */}
                    {step === 2 && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
                            <div className="text-center mb-8">
                                <div className="w-16 h-16 mx-auto rounded-2xl bg-gradient-to-br from-violet-500 to-purple-500 flex items-center justify-center mb-4">
                                    <FileText size={32} className="text-white" />
                                </div>
                                <h2 className="text-xl font-semibold">Add Details</h2>
                                <p className="text-muted-foreground mt-1">Describe your item to attract buyers</p>
                            </div>

                            {/* Image upload */}
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-2">
                                    Photos (up to 5)
                                </label>
                                <div className="grid grid-cols-5 gap-3">
                                    {images.map((img, index) => (
                                        <div key={index} className="relative aspect-square rounded-lg overflow-hidden">
                                            <img src={img} alt="" className="w-full h-full object-cover" />
                                            <button
                                                onClick={() => removeImage(index)}
                                                className="absolute top-1 right-1 p-1 rounded-full bg-black/50 hover:bg-black/70 transition-colors"
                                            >
                                                <X size={14} className="text-white" />
                                            </button>
                                        </div>
                                    ))}
                                    {images.length < 5 && (
                                        <label className="aspect-square rounded-lg border-2 border-dashed border-border hover:border-primary flex flex-col items-center justify-center cursor-pointer transition-colors">
                                            <Camera size={24} className="text-muted-foreground mb-1" />
                                            <span className="text-xs text-muted-foreground">Add</span>
                                            <input
                                                type="file"
                                                accept="image/*"
                                                multiple
                                                onChange={handleImageUpload}
                                                className="hidden"
                                            />
                                        </label>
                                    )}
                                </div>
                            </div>

                            <Input
                                label="Title"
                                name="title"
                                placeholder="e.g., Engineering Mathematics Textbook"
                                value={formData.title}
                                onChange={handleChange}
                                icon={<Package size={18} />}
                            />

                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-1.5">
                                    Description
                                </label>
                                <textarea
                                    name="description"
                                    placeholder="Describe your item in detail. Include brand, size, any defects, etc."
                                    value={formData.description}
                                    onChange={handleChange}
                                    rows={4}
                                    className="w-full bg-input border border-border rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/20 transition-all"
                                />
                            </div>

                            <Input
                                label="Price (Γé╣)"
                                name="price"
                                type="number"
                                placeholder="Enter your asking price"
                                value={formData.price}
                                onChange={handleChange}
                                icon={<DollarSign size={18} />}
                            />

                            {formData.price && (
                                <div className="p-3 rounded-lg bg-amber-500/10 border border-amber-500/20">
                                    <div className="flex items-start gap-2">
                                        <AlertCircle size={16} className="text-amber-500 mt-0.5 flex-shrink-0" />
                                        <div className="text-sm">
                                            <p className="text-amber-200">
                                                You'll receive <span className="font-semibold text-emerald-400">Γé╣{Math.round(parseFloat(formData.price) * 0.95).toLocaleString()}</span> after 5% platform fee
                                            </p>
                                            <p className="text-xs text-muted-foreground mt-1">
                                                CampusMarket charges 5% from sellers. Adjust your price accordingly.
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}

                    {/* Step 3: Availability */}
                    {step === 3 && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
                            <div className="text-center mb-8">
                                <div className="w-16 h-16 mx-auto rounded-2xl bg-gradient-to-br from-cyan-500 to-blue-500 flex items-center justify-center mb-4">
                                    <Calendar size={32} className="text-white" />
                                </div>
                                <h2 className="text-xl font-semibold">When are you available?</h2>
                                <p className="text-muted-foreground mt-1">Let buyers know when you can meet for delivery</p>
                            </div>

                            {/* Days selection */}
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-3">
                                    Available Days
                                </label>
                                <div className="flex flex-wrap gap-2">
                                    {weekdays.map((day) => (
                                        <button
                                            key={day.value}
                                            type="button"
                                            onClick={() => toggleDay(day.value)}
                                            className={`px-4 py-2 rounded-lg font-medium transition-all ${formData.availableDays.includes(day.value)
                                                ? "bg-primary text-white"
                                                : "bg-muted text-muted-foreground hover:bg-muted/80"
                                                }`}
                                        >
                                            {day.label}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Time range */}
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-muted-foreground mb-1.5">
                                        From
                                    </label>
                                    <div className="relative">
                                        <Clock size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                        <input
                                            type="time"
                                            name="availableTimeStart"
                                            value={formData.availableTimeStart}
                                            onChange={handleChange}
                                            className="w-full bg-input border border-border rounded-lg pl-10 pr-4 py-2.5 focus:outline-none focus:border-primary"
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-muted-foreground mb-1.5">
                                        To
                                    </label>
                                    <div className="relative">
                                        <Clock size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                        <input
                                            type="time"
                                            name="availableTimeEnd"
                                            value={formData.availableTimeEnd}
                                            onChange={handleChange}
                                            className="w-full bg-input border border-border rounded-lg pl-10 pr-4 py-2.5 focus:outline-none focus:border-primary"
                                        />
                                    </div>
                                </div>
                            </div>

                            {/* Note */}
                            <div>
                                <label className="block text-sm font-medium text-muted-foreground mb-1.5">
                                    Additional Note (optional)
                                </label>
                                <input
                                    type="text"
                                    name="availableNote"
                                    value={formData.availableNote}
                                    onChange={handleChange}
                                    placeholder="e.g., Free after 3rd lecture, or only during lunch break"
                                    className="w-full bg-input border border-border rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:border-primary"
                                    maxLength={200}
                                />
                            </div>
                        </div>
                    )}

                    {/* Step 4: College & Preview */}
                    {step === 4 && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
                            <div className="text-center mb-8">
                                <div className="w-16 h-16 mx-auto rounded-2xl bg-gradient-to-br from-emerald-500 to-teal-500 flex items-center justify-center mb-4">
                                    <Sparkles size={32} className="text-white" />
                                </div>
                                <h2 className="text-xl font-semibold">Almost Done!</h2>
                                <p className="text-muted-foreground mt-1">Select your college to list the item</p>
                            </div>

                            <Select
                                label="College"
                                name="college"
                                value={formData.college}
                                onChange={handleChange}
                                options={[
                                    { value: "", label: "Select your college" },
                                    ...colleges.map(c => ({ value: c._id, label: `${c.name} (${c.shortCode})` }))
                                ]}
                            />

                            {/* Preview */}
                            <div className="mt-8 p-6 rounded-xl bg-muted/30 border border-border">
                                <h3 className="font-semibold mb-4">Listing Preview</h3>
                                <div className="flex gap-4">
                                    <div className="w-24 h-24 rounded-lg bg-muted flex items-center justify-center overflow-hidden">
                                        {images[0] ? (
                                            <img src={images[0]} alt="" className="w-full h-full object-cover" />
                                        ) : (
                                            <Package size={32} className="text-muted-foreground" />
                                        )}
                                    </div>
                                    <div className="flex-1">
                                        <h4 className="font-medium">{formData.title || "Your Item Title"}</h4>
                                        <p className="text-sm text-muted-foreground mt-1 line-clamp-2">
                                            {formData.description || "Item description..."}
                                        </p>
                                        <div className="flex items-center gap-3 mt-2">
                                            <span className="price-tag">Γé╣{formData.price || "0"}</span>
                                            <span className="badge badge-primary">{formData.condition}</span>
                                        </div>
                                    </div>
                                </div>

                                {/* Availability preview */}
                                {formData.availableDays.length > 0 && (
                                    <div className="mt-4 pt-4 border-t border-border">
                                        <div className="flex items-center gap-2 text-sm">
                                            <Calendar size={14} className="text-primary" />
                                            <span className="text-muted-foreground">Available:</span>
                                            <span>{formData.availableDays.map(d => d.slice(0, 3)).join(", ")}</span>
                                            <span className="text-muted-foreground">|</span>
                                            <span>{formData.availableTimeStart} - {formData.availableTimeEnd}</span>
                                        </div>
                                        {formData.availableNote && (
                                            <p className="text-xs text-muted-foreground mt-1">"{formData.availableNote}"</p>
                                        )}
                                    </div>
                                )}
                            </div>

                            {/* Fee disclaimer */}
                            <p className="text-xs text-muted-foreground text-center">
                                By listing, you agree to CampusMarket's terms. A 5% platform fee will be deducted from the sale price.
                            </p>
                        </div>
                    )}

                    {/* Navigation */}
                    <div className="flex items-center justify-between mt-8 pt-6 border-t border-border">
                        {step > 1 ? (
                            <Button variant="ghost" onClick={() => setStep(step - 1)} icon={<ArrowLeft size={18} />}>
                                Back
                            </Button>
                        ) : (
                            <div />
                        )}

                        {step < 4 ? (
                            <Button
                                variant="primary"
                                onClick={() => setStep(step + 1)}
                                disabled={!canProceed()}
                                icon={<ArrowRight size={18} />}
                            >
                                Continue
                            </Button>
                        ) : (
                            <Button
                                variant="accent"
                                onClick={handleSubmit}
                                disabled={!canProceed() || loading}
                                loading={loading}
                                icon={<Sparkles size={18} />}
                            >
                                List Item
                            </Button>
                        )}
                    </div>
                </Card>
            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { Modal } from "@/components/ui/Modal";
import { Button } from "@/components/ui/Button";
import { Card } from "@/components/ui/Card";
import { CheckCircle, FileText, Shield, AlertTriangle } from "lucide-react";

interface AgreementModalProps {
    isOpen: boolean;
    onClose: () => void;
    onAccept: (terms: string, signature: string) => void;
    product: {
        title: string;
        price: number;
    };
    seller: {
        name: string;
    };
    buyer: {
        name: string;
    };
    totalAmount: number;
    buyerFee: number;
    sellerFee: number;
}

const AGREEMENT_TERMS = `
PURCHASE AGREEMENT - CAMPUSMARKET

This agreement ("Agreement") is entered into between the Buyer and Seller through CampusMarket platform.

1. PRODUCT SALE
The Seller agrees to sell and the Buyer agrees to purchase the listed product at the agreed price plus applicable platform fees.

2. PAYMENT & ESCROW
ΓÇó Payment is processed securely through Razorpay
ΓÇó Funds are held in escrow by CampusMarket until delivery is confirmed
ΓÇó Platform fee of 5% is charged to both Buyer and Seller

3. DELIVERY TERMS
ΓÇó Seller must deliver the product at the agreed campus location and time
ΓÇó Buyer must inspect the product upon receipt
ΓÇó Buyer must confirm receipt within 24 hours of delivery

4. REFUND POLICY
ΓÇó If Seller fails to deliver: Full refund to Buyer
ΓÇó If product differs significantly from description: Buyer may reject and receive refund
ΓÇó Once delivery is confirmed: No refunds

5. DISPUTE RESOLUTION
ΓÇó Both parties agree to resolve disputes through CampusMarket support
ΓÇó CampusMarket's decision on disputes is final

6. LIABILITY
ΓÇó CampusMarket acts only as a platform facilitator
ΓÇó Buyer and Seller are responsible for the transaction
ΓÇó CampusMarket is not liable for product quality or disputes

7. DIGITAL SIGNATURES
ΓÇó By accepting this agreement, both parties provide their digital signature
ΓÇó This agreement is legally binding

By proceeding with this transaction, both parties acknowledge they have read, understood, and agree to these terms.
`.trim();

export function AgreementModal({
    isOpen,
    onClose,
    onAccept,
    product,
    seller,
    buyer,
    totalAmount,
    buyerFee,
    sellerFee,
}: AgreementModalProps) {
    const [agreed, setAgreed] = useState(false);
    const [signature, setSignature] = useState("");

    const handleAccept = () => {
        if (!agreed || !signature.trim()) return;
        onAccept(AGREEMENT_TERMS, signature);
    };

    const currentDate = new Date().toLocaleDateString("en-IN", {
        year: "numeric",
        month: "long",
        day: "numeric",
    });

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Purchase Agreement" size="lg">
            <div className="p-6 space-y-6">
                {/* Agreement Header */}
                <Card variant="gradient" className="p-4">
                    <div className="flex items-center gap-3 mb-3">
                        <FileText size={24} className="text-primary" />
                        <h3 className="font-semibold">Digital Purchase Agreement</h3>
                    </div>
                    <div className="grid grid-cols-2 gap-4 text-sm">
                        <div>
                            <span className="text-muted-foreground">Product:</span>
                            <p className="font-medium">{product.title}</p>
                        </div>
                        <div>
                            <span className="text-muted-foreground">Date:</span>
                            <p className="font-medium">{currentDate}</p>
                        </div>
                        <div>
                            <span className="text-muted-foreground">Seller:</span>
                            <p className="font-medium">{seller.name}</p>
                        </div>
                        <div>
                            <span className="text-muted-foreground">Buyer:</span>
                            <p className="font-medium">{buyer.name}</p>
                        </div>
                    </div>
                </Card>

                {/* Fee Breakdown */}
                <Card className="p-4 bg-muted/30">
                    <h4 className="font-medium mb-3 flex items-center gap-2">
                        <Shield size={18} className="text-emerald-500" />
                        Payment Breakdown
                    </h4>
                    <div className="space-y-2 text-sm">
                        <div className="flex justify-between">
                            <span>Product Price</span>
                            <span>Γé╣{product.price.toLocaleString()}</span>
                        </div>
                        <div className="flex justify-between text-muted-foreground">
                            <span>Platform Fee (5%)</span>
                            <span>+ Γé╣{buyerFee.toLocaleString()}</span>
                        </div>
                        <div className="flex justify-between font-semibold pt-2 border-t border-border">
                            <span>You Pay</span>
                            <span className="text-primary">Γé╣{totalAmount.toLocaleString()}</span>
                        </div>
                    </div>
                </Card>

                {/* Terms */}
                <div>
                    <h4 className="font-medium mb-2">Terms & Conditions</h4>
                    <div className="h-48 overflow-y-auto p-4 bg-muted/20 rounded-lg border border-border text-sm whitespace-pre-line">
                        {AGREEMENT_TERMS}
                    </div>
                </div>

                {/* Warning */}
                <div className="flex items-start gap-3 p-3 rounded-lg bg-amber-500/10 border border-amber-500/20">
                    <AlertTriangle size={20} className="text-amber-500 flex-shrink-0 mt-0.5" />
                    <p className="text-sm text-amber-200">
                        By typing your name and accepting, you are digitally signing this agreement.
                        This is a legally binding transaction.
                    </p>
                </div>

                {/* Digital Signature */}
                <div>
                    <label className="block text-sm font-medium mb-2">
                        Your Digital Signature (Type your full name)
                    </label>
                    <input
                        type="text"
                        value={signature}
                        onChange={(e) => setSignature(e.target.value)}
                        placeholder="Enter your full name"
                        className="w-full bg-input border border-border rounded-lg px-4 py-3 text-lg font-signature focus:outline-none focus:border-primary"
                        style={{ fontFamily: "'Brush Script MT', cursive" }}
                    />
                </div>

                {/* Checkbox */}
                <label className="flex items-start gap-3 cursor-pointer">
                    <input
                        type="checkbox"
                        checked={agreed}
                        onChange={(e) => setAgreed(e.target.checked)}
                        className="mt-1 w-5 h-5 rounded border-border accent-primary"
                    />
                    <span className="text-sm">
                        I have read and agree to the terms and conditions above.
                        I understand this is a binding agreement.
                    </span>
                </label>

                {/* Actions */}
                <div className="flex gap-3 pt-4 border-t border-border">
                    <Button variant="ghost" onClick={onClose} className="flex-1">
                        Cancel
                    </Button>
                    <Button
                        variant="accent"
                        onClick={handleAccept}
                        disabled={!agreed || signature.trim().length < 2}
                        icon={<CheckCircle size={18} />}
                        className="flex-1"
                    >
                        Accept & Continue to Payment
                    </Button>
                </div>
            </div>
        </Modal>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { Button } from "@/components/ui/Button";
import { Avatar } from "@/components/ui/Avatar";
import { cn } from "@/lib/utils";
import {
    Menu,
    X,
    Search,
    ShoppingBag,
    PlusCircle,
    User,
    LogOut,
    LayoutDashboard,
    Sun,
    Moon,
    Wallet
} from "lucide-react";

interface User {
    id: string;
    name: string;
    email: string;
    wallet?: number;
    profileImage?: string;
    college?: {
        name: string;
        shortCode: string;
    };
}

export function Navbar() {
    const [isScrolled, setIsScrolled] = useState(false);
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const [isDark, setIsDark] = useState(true);
    const [user, setUser] = useState<User | null>(null);
    const pathname = usePathname();

    // Check scroll position
    useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 20);
        };
        window.addEventListener("scroll", handleScroll);
        return () => window.removeEventListener("scroll", handleScroll);
    }, []);

    // Load user from localStorage
    useEffect(() => {
        const savedUser = localStorage.getItem("user");
        if (savedUser) {
            setUser(JSON.parse(savedUser));
        }
    }, []);

    // Theme toggle
    useEffect(() => {
        document.documentElement.classList.toggle("light", !isDark);
    }, [isDark]);

    const handleLogout = () => {
        localStorage.removeItem("user");
        localStorage.removeItem("token");
        setUser(null);
        window.location.href = "/";
    };

    const navLinks = [
        { href: "/browse", label: "Browse" },
        { href: "/categories", label: "Categories" },
        { href: "/how-it-works", label: "How it Works" },
    ];

    return (
        <nav
            className={cn(
                "fixed top-0 left-0 right-0 z-50 transition-all duration-300",
                isScrolled
                    ? "bg-background/80 backdrop-blur-lg border-b border-border shadow-lg"
                    : "bg-transparent"
            )}
        >
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex items-center justify-between h-16">
                    {/* Logo */}
                    <Link href="/" className="flex items-center gap-2">
                        <img
                            src="/logo.svg"
                            alt="CampusMarket Logo"
                            className="w-10 h-10 object-contain rounded-xl"
                        />
                        <span className="text-xl font-bold gradient-text hidden sm:block">
                            CampusMarket
                        </span>
                    </Link>

                    {/* Desktop Nav Links */}
                    <div className="hidden md:flex items-center gap-6">
                        {navLinks.map((link) => (
                            <Link
                                key={link.href}
                                href={link.href}
                                className={cn(
                                    "text-sm font-medium transition-colors hover:text-primary",
                                    pathname === link.href ? "text-primary" : "text-muted-foreground"
                                )}
                            >
                                {link.label}
                            </Link>
                        ))}
                    </div>

                    {/* Search (Desktop) */}
                    <div className="hidden lg:flex items-center flex-1 max-w-md mx-8">
                        <div className="relative w-full">
                            <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                            <input
                                type="text"
                                placeholder="Search for books, electronics, furniture..."
                                className="w-full bg-input border border-border rounded-full pl-10 pr-4 py-2 text-sm focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/20"
                            />
                        </div>
                    </div>

                    {/* Right side actions */}
                    <div className="flex items-center gap-3">
                        {/* Theme toggle */}
                        <button
                            onClick={() => setIsDark(!isDark)}
                            className="p-2 rounded-lg hover:bg-muted transition-colors hidden sm:flex"
                        >
                            {isDark ? <Sun size={20} /> : <Moon size={20} />}
                        </button>

                        {user ? (
                            <>
                                {/* Sell button */}
                                <Link href="/sell">
                                    <Button variant="primary" size="sm" icon={<PlusCircle size={16} />} className="hidden sm:flex">
                                        Sell
                                    </Button>
                                </Link>

                                {/* Profile dropdown */}
                                <div className="relative">
                                    <button
                                        onClick={() => setIsProfileOpen(!isProfileOpen)}
                                        className="flex items-center gap-2 p-1.5 rounded-full hover:bg-muted transition-colors"
                                    >
                                        <Avatar src={user.profileImage} name={user.name} size="sm" />
                                    </button>

                                    {isProfileOpen && (
                                        <>
                                            <div
                                                className="fixed inset-0"
                                                onClick={() => setIsProfileOpen(false)}
                                            />
                                            <div className="absolute right-0 mt-2 w-64 bg-card border border-border rounded-xl shadow-xl overflow-hidden animate-in slide-in-from-top-2">
                                                <div className="p-4 border-b border-border">
                                                    <p className="font-semibold">{user.name}</p>
                                                    <p className="text-sm text-muted-foreground">{user.email}</p>
                                                    {user.college && (
                                                        <span className="inline-block mt-2 text-xs bg-primary/10 text-primary px-2 py-1 rounded-full">
                                                            {user.college.shortCode}
                                                        </span>
                                                    )}
                                                </div>
                                                <div className="p-2">
                                                    <Link
                                                        href="/dashboard"
                                                        className="flex items-center gap-3 px-3 py-2 text-sm rounded-lg hover:bg-muted transition-colors"
                                                    >
                                                        <LayoutDashboard size={18} />
                                                        Dashboard
                                                    </Link>
                                                    <Link
                                                        href="/profile"
                                                        className="flex items-center gap-3 px-3 py-2 text-sm rounded-lg hover:bg-muted transition-colors"
                                                    >
                                                        <User size={18} />
                                                        Profile
                                                    </Link>
                                                    <div className="flex items-center gap-3 px-3 py-2 text-sm rounded-lg bg-gradient-to-r from-emerald-500/10 to-transparent">
                                                        <Wallet size={18} className="text-emerald-500" />
                                                        <span>Wallet:</span>
                                                        <span className="font-semibold text-emerald-500">
                                                            Γé╣{(user.wallet || 0).toLocaleString()}
                                                        </span>
                                                    </div>
                                                </div>
                                                <div className="p-2 border-t border-border">
                                                    <button
                                                        onClick={handleLogout}
                                                        className="flex items-center gap-3 px-3 py-2 text-sm rounded-lg hover:bg-destructive/10 text-destructive w-full transition-colors"
                                                    >
                                                        <LogOut size={18} />
                                                        Logout
                                                    </button>
                                                </div>
                                            </div>
                                        </>
                                    )}
                                </div>
                            </>
                        ) : (
                            <div className="flex items-center gap-2">
                                <Link href="/login">
                                    <Button variant="ghost" size="sm">Login</Button>
                                </Link>
                                <Link href="/register">
                                    <Button variant="primary" size="sm">Get Started</Button>
                                </Link>
                            </div>
                        )}

                        {/* Mobile menu button */}
                        <button
                            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                            className="p-2 rounded-lg hover:bg-muted transition-colors md:hidden"
                        >
                            {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
                        </button>
                    </div>
                </div>
            </div>

            {/* Mobile menu overlay */}
            {isMobileMenuOpen && (
                <div
                    className="fixed inset-0 bg-background/60 backdrop-blur-sm z-40 md:hidden"
                    onClick={() => setIsMobileMenuOpen(false)}
                />
            )}

            {/* Mobile menu drawer */}
            <div className={cn(
                "fixed top-0 right-0 bottom-0 w-[280px] bg-card border-l border-border z-50 md:hidden transition-transform duration-300 ease-in-out transform",
                isMobileMenuOpen ? "translate-x-0" : "translate-x-full"
            )}>
                <div className="flex flex-col h-full">
                    {/* Drawer Header */}
                    <div className="p-4 border-b border-border flex items-center justify-between bg-muted/30">
                        <span className="font-bold gradient-text">CampusMarket</span>
                        <button
                            onClick={() => setIsMobileMenuOpen(false)}
                            className="p-1 rounded-lg hover:bg-muted"
                        >
                            <X size={20} />
                        </button>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 space-y-6">
                        {/* User Profile info in drawer */}
                        {user ? (
                            <div className="bg-muted/50 rounded-xl p-4 border border-border">
                                <div className="flex items-center gap-3 mb-4">
                                    <Avatar src={user.profileImage} name={user.name} size="md" />
                                    <div className="flex-1 min-w-0">
                                        <p className="font-semibold truncate">{user.name}</p>
                                        <p className="text-xs text-muted-foreground truncate">{user.email}</p>
                                    </div>
                                </div>
                                <div className="grid grid-cols-2 gap-2">
                                    <div className="bg-background rounded-lg p-2 border border-border">
                                        <p className="text-[10px] text-muted-foreground uppercase">Wallet</p>
                                        <p className="text-sm font-bold text-emerald-500">Γé╣{(user.wallet || 0).toLocaleString()}</p>
                                    </div>
                                    <div className="bg-background rounded-lg p-2 border border-border">
                                        <p className="text-[10px] text-muted-foreground uppercase">College</p>
                                        <p className="text-sm font-bold text-primary truncate">{user.college?.shortCode || "N/A"}</p>
                                    </div>
                                </div>
                            </div>
                        ) : (
                            <div className="space-y-2">
                                <Link href="/login" onClick={() => setIsMobileMenuOpen(false)}>
                                    <Button variant="outline" className="w-full">Login</Button>
                                </Link>
                                <Link href="/register" onClick={() => setIsMobileMenuOpen(false)}>
                                    <Button variant="primary" className="w-full">Get Started</Button>
                                </Link>
                            </div>
                        )}

                        {/* Navigation Section */}
